def _human_gate_short_id(scenario_id: str) -> str:
    return scenario_id.replace("CS-CH-", "")


def _human_gate_product_feature_claim(scenario_id: str, operation: str) -> str:
    return (
        f"CONNECTOR_HUB_{_human_gate_short_id(scenario_id)}_{operation}"
        "_PREPARED_HUMAN_EVIDENCE_REQUIRED"
    )


def _expected_evidence_packet_required_labels(
    expected_required_evidence_labels: list[object] | None,
) -> list[str]:
    if expected_required_evidence_labels is None:
        return list(EXPECTED_H04_EVIDENCE_PACKET_REQUIRED_LABELS)
    return [str(label) for label in expected_required_evidence_labels]


def _expected_evidence_packet_manifest(labels: list[str]) -> list[dict[str, object]]:
    return [
        {
            "required_evidence_index": index,
            "required_evidence": label,
        }
        for index, label in enumerate(labels, start=1)
    ]


def _expected_evidence_packet_file_items(scenario_id: str) -> list[dict[str, object]]:
    return [
        dict(item)
        for item in EXPECTED_EVIDENCE_PACKET_FILE_ITEMS_BY_SCENARIO[scenario_id]
    ]


def _expected_evidence_packet_scaffold_directory(scenario_id: str) -> str:
    return EXPECTED_EVIDENCE_PACKET_FILE_SCAFFOLD_DIRECTORY_BY_SCENARIO[scenario_id]


def _expected_evidence_packet_scaffold_command_count(scenario_id: str) -> int:
    return len(EXPECTED_EVIDENCE_PACKET_FILE_ITEMS_BY_SCENARIO[scenario_id]) + 1


def _expected_evidence_packet_scaffold_template_content(
    packet_file: str,
    required_contents: str,
    scenario_id: str = "CS-CH-H04",
) -> str:
    short_scenario = _human_gate_short_id(scenario_id)
    if packet_file.endswith(".json"):
        template = {
            "scenario_id": scenario_id,
            "status": "TEMPLATE_ONLY_NOT_HUMAN_EVIDENCE",
            "packet_file": packet_file,
            "required_contents": required_contents,
            "evidence_ref": "",
            "redaction_status": "",
            "reviewer": "",
            "review_timestamp": "",
            "notes": "",
            "operator_warning": f"Do not mark {short_scenario} PASS from this template file.",
            "acceptance_claim": "HUMAN_REQUIRED_UNTIL_OWNER_ACCEPT_RECORD",
        }
        return json.dumps(template, indent=2, sort_keys=True) + "\n"
    if packet_file.endswith(".md"):
        return (
            f"# {short_scenario} Evidence Packet Template: {packet_file}\n\n"
            "Status: TEMPLATE_ONLY_NOT_HUMAN_EVIDENCE\n"
            f"Scenario: {scenario_id}\n\n"
            "## Required Contents\n\n"
            f"{required_contents}\n\n"
            "## Evidence Ref\n\n"
            "- evidence_ref:\n"
            "- redaction_status:\n"
            "- reviewer:\n"
            "- review_timestamp:\n\n"
            "## Notes\n\n"
            "- Keep secrets and private payloads redacted.\n"
            f"- Do not mark {short_scenario} PASS from this template file.\n"
        )
    return (
        f"{short_scenario} Evidence Packet Template: {packet_file}\n"
        "Status: TEMPLATE_ONLY_NOT_HUMAN_EVIDENCE\n"
        f"Scenario: {scenario_id}\n\n"
        "Required Contents:\n"
        f"{required_contents}\n\n"
        "Evidence Ref:\n"
        "Redaction Status:\n"
        "Reviewer:\n"
        "Review Timestamp:\n\n"
        "Notes:\n"
        "- Keep secrets and private payloads redacted.\n"
        f"- Do not mark {short_scenario} PASS from this template file.\n"
    )


def _expected_h04_evidence_packet_scaffold_template_content(
    packet_file: str,
    required_contents: str,
) -> str:
    return _expected_evidence_packet_scaffold_template_content(
        packet_file,
        required_contents,
        "CS-CH-H04",
    )


def _expected_evidence_packet_scaffold_templates(
    scenario_id: str,
) -> list[dict[str, object]]:
    templates: list[dict[str, object]] = []
    for item in _expected_evidence_packet_file_items(scenario_id):
        packet_file = str(item["packet_file"])
        required_contents = str(item["required_contents"])
        content = _expected_evidence_packet_scaffold_template_content(
            packet_file,
            required_contents,
            scenario_id,
        )
        templates.append(
            {
                "packet_file": packet_file,
                "required": True,
                "required_contents": required_contents,
                "template_only": True,
                "template_content_sha256": hashlib.sha256(
                    content.encode("utf-8")
                ).hexdigest(),
                "template_content_line_count": len(content.splitlines()),
                "human_evidence_recorded_by_template": False,
                "acceptance_sufficient": False,
                "product_claim_allowed": False,
                "pass_claim_allowed": False,
                "packet_file_contents_read_by_scaffold": False,
            }
        )
    return templates


def _expected_h04_evidence_packet_scaffold_templates() -> list[dict[str, object]]:
    return _expected_evidence_packet_scaffold_templates("CS-CH-H04")


def _file_metadata(path: Path) -> dict[str, object]:
    data = path.read_bytes()
    line_count = data.count(b"\n")
    if data and not data.endswith(b"\n"):
        line_count += 1
    return {
        "sha256": hashlib.sha256(data).hexdigest(),
        "size_bytes": len(data),
        "line_count": line_count,
    }
