def _source_verification_plan_item_count(section_id: str) -> int:
    for section in SOURCE_VERIFICATION_PLAN_SECTIONS:
        if section["section_id"] == section_id:
            return len(section["items"])
    raise AssertionError(f"unknown source verification plan section: {section_id}")


