def _read_matrix() -> list[dict[str, str]]:
    with MATRIX_PATH.open(newline="") as file:
        return list(csv.DictReader(file))


def _matrix_fieldnames() -> list[str]:
    with MATRIX_PATH.open(newline="") as file:
        return list(csv.DictReader(file).fieldnames or [])


def _validate_matrix_ledger(errors: list[str], matrix_rows: list[dict[str, str]]) -> None:
    fieldnames = _matrix_fieldnames()
    if fieldnames != EXPECTED_MATRIX_COLUMNS:
        errors.append(
            "ConnectorHub matrix columns changed: "
            f"expected {EXPECTED_MATRIX_COLUMNS}, found {fieldnames}"
        )

    scenario_ids = [row.get("scenario_id", "") for row in matrix_rows]
    duplicate_ids = sorted(
        scenario_id
        for scenario_id, count in Counter(scenario_ids).items()
        if scenario_id and count > 1
    )
    if duplicate_ids:
        errors.append(f"ConnectorHub matrix has duplicate scenario IDs: {', '.join(duplicate_ids)}")

    expected_ids = EXPECTED_AI_SCENARIO_IDS | EXPECTED_HUMAN_SCENARIO_IDS
    observed_ids = set(scenario_ids)
    missing_ids = sorted(expected_ids - observed_ids)
    unexpected_ids = sorted(observed_ids - expected_ids)
    if missing_ids:
        errors.append(f"ConnectorHub matrix missing scenario IDs: {', '.join(missing_ids)}")
    if unexpected_ids:
        errors.append(f"ConnectorHub matrix has unexpected scenario IDs: {', '.join(unexpected_ids)}")

    type_counts = Counter(row.get("type", "") for row in matrix_rows)
    owner_counts = Counter(row.get("owner", "") for row in matrix_rows)
    status_counts = Counter(row.get("status", "") for row in matrix_rows)
    if dict(type_counts) != EXPECTED_MATRIX_TYPE_COUNTS:
        errors.append(
            "ConnectorHub matrix type counts changed: "
            f"expected {EXPECTED_MATRIX_TYPE_COUNTS}, found {dict(type_counts)}"
        )
    if dict(owner_counts) != EXPECTED_MATRIX_OWNER_COUNTS:
        errors.append(
            "ConnectorHub matrix owner counts changed: "
            f"expected {EXPECTED_MATRIX_OWNER_COUNTS}, found {dict(owner_counts)}"
        )
    if dict(status_counts) != EXPECTED_MATRIX_STATUS_COUNTS:
        errors.append(
            "ConnectorHub matrix status counts changed: "
            f"expected {EXPECTED_MATRIX_STATUS_COUNTS}, found {dict(status_counts)}"
        )
    for scenario_type, expected_type_ids in EXPECTED_MATRIX_TYPE_SCENARIO_IDS.items():
        observed_type_ids = {
            row.get("scenario_id", "")
            for row in matrix_rows
            if row.get("type") == scenario_type
        }
        missing_type_ids = sorted(expected_type_ids - observed_type_ids)
        unexpected_type_ids = sorted(observed_type_ids - expected_type_ids)
        if missing_type_ids:
            errors.append(
                f"ConnectorHub matrix {scenario_type} missing scenario IDs: "
                f"{', '.join(missing_type_ids)}"
            )
        if unexpected_type_ids:
            errors.append(
                f"ConnectorHub matrix {scenario_type} has unexpected scenario IDs: "
                f"{', '.join(unexpected_type_ids)}"
            )
    for phase, expected_phase_ids in EXPECTED_MATRIX_PHASE_SCENARIO_IDS.items():
        observed_phase_ids = {
            row.get("scenario_id", "")
            for row in matrix_rows
            if row.get("phase") == phase
        }
        missing_phase_ids = sorted(expected_phase_ids - observed_phase_ids)
        unexpected_phase_ids = sorted(observed_phase_ids - expected_phase_ids)
        if missing_phase_ids:
            errors.append(
                f"ConnectorHub matrix {phase} missing scenario IDs: "
                f"{', '.join(missing_phase_ids)}"
            )
        if unexpected_phase_ids:
            errors.append(
                f"ConnectorHub matrix {phase} has unexpected scenario IDs: "
                f"{', '.join(unexpected_phase_ids)}"
            )

    for row in matrix_rows:
        scenario_id = row.get("scenario_id", "")
        proof_surface = row.get("proof_surface", "")
        claim_boundary = row.get("claim_boundary", "")
        evidence_required = row.get("evidence_required", "")
        related_requirements = row.get("related_requirements", "")
        for column in EXPECTED_MATRIX_COLUMNS:
            if not row.get(column, "").strip():
                errors.append(f"{scenario_id or '<missing id>'} matrix row missing {column}")
        expected_related_requirements = EXPECTED_MATRIX_RELATED_REQUIREMENTS_BY_SCENARIO.get(
            scenario_id
        )
        if expected_related_requirements is None:
            errors.append(
                f"{scenario_id} matrix row has no related_requirements expectation"
            )
        elif _requirement_ids(related_requirements) != expected_related_requirements:
            errors.append(
                f"{scenario_id} matrix related_requirements expected "
                f"{';'.join(expected_related_requirements)}, found {related_requirements}"
            )
        expected_matrix_text = EXPECTED_MATRIX_TEXT_BY_SCENARIO.get(scenario_id)
        if expected_matrix_text is None:
            errors.append(f"{scenario_id} matrix row has no text-field expectation")
        else:
            for field_name, expected_value in expected_matrix_text.items():
                observed_value = row.get(field_name, "")
                if observed_value != expected_value:
                    errors.append(
                        f"{scenario_id} matrix {field_name} expected "
                        f"{expected_value!r}, found {observed_value!r}"
                    )
        if row.get("phase") not in EXPECTED_MATRIX_PHASES:
            errors.append(f"{scenario_id} matrix phase is unexpected: {row.get('phase')}")
        expected_claim_boundary = EXPECTED_MATRIX_CLAIM_BOUNDARY_BY_PROOF_SURFACE.get(
            proof_surface
        )
        if expected_claim_boundary is None:
            errors.append(
                f"{scenario_id} matrix proof_surface has no claim-boundary rule: {proof_surface}"
            )
        elif claim_boundary != expected_claim_boundary:
            errors.append(
                f"{scenario_id} matrix claim_boundary expected {expected_claim_boundary!r}, "
                f"found {claim_boundary!r}"
            )
        if scenario_id in EXPECTED_AI_SCENARIO_IDS:
            expected_ai_evidence_required = _expected_ai_evidence_required(scenario_id)
            if evidence_required != expected_ai_evidence_required:
                errors.append(
                    f"{scenario_id} AI matrix evidence_required expected "
                    f"{expected_ai_evidence_required}, found {evidence_required}"
                )
            if row.get("owner") != "AI" or row.get("status") != "PASS":
                errors.append(f"{scenario_id} AI scenario must be owner=AI and status=PASS")
            if row.get("type") not in {"MUST_PASS", "REGRESSION_GUARD"}:
                errors.append(f"{scenario_id} AI scenario has unexpected type: {row.get('type')}")
            if row.get("proof_surface") not in {"local_fixture", "local_vs2_topology"}:
                errors.append(f"{scenario_id} AI scenario has unexpected proof_surface: {row.get('proof_surface')}")
        elif scenario_id in EXPECTED_HUMAN_SCENARIO_IDS:
            expected_human_template = _expected_human_review_template_path(scenario_id)
            if expected_human_template not in evidence_required:
                errors.append(
                    f"{scenario_id} human matrix evidence_required must include "
                    f"{expected_human_template}"
                )
            if (
                row.get("type") != "HUMAN_REQUIRED"
                or row.get("owner") != "Human"
                or row.get("status") != "HUMAN_REQUIRED"
                or row.get("proof_surface") != "human_required"
            ):
                errors.append(f"{scenario_id} human scenario must remain HUMAN_REQUIRED/human_required")


def _scenario_number(scenario_id: str) -> int:
    match = re.fullmatch(r"CS-CH-(\d{3})", scenario_id)
    return int(match.group(1)) if match else -1


def _markdown_section(text: str, heading: str) -> str | None:
    match = re.search(
        rf"\n## {re.escape(heading)}\n\n(?P<section>.*?)(?=\n## [^\n]+\n|\Z)",
        text,
        flags=re.S,
    )
    return match.group("section") if match else None


def _markdown_subsection(text: str, heading: str) -> str | None:
    match = re.search(
        rf"\n### {re.escape(heading)}\n\n(?P<section>.*?)(?=\n### [^\n]+\n|\n## [^\n]+\n|\Z)",
        text,
        flags=re.S,
    )
    return match.group("section") if match else None


def _markdown_bullet_values(section: str, labels: list[str]) -> dict[str, str]:
    values: dict[str, str] = {}
    for label in labels:
        match = re.search(rf"^- {re.escape(label)}:\s*(.*)$", section, flags=re.M)
        values[label] = match.group(1).strip() if match else ""
    return values


def _lifecycle_marker_order_facts(section: str | None) -> dict[str, object]:
    text = section or ""
    positions = {
        marker: text.find(f"- {marker}:")
        for marker in REQUIRED_LIFECYCLE_STEP_ORDER
    }
    missing = [
        marker
        for marker, position in positions.items()
        if position < 0
    ]
    actual = [
        marker
        for marker, _position in sorted(
            (
                (marker, position)
                for marker, position in positions.items()
                if position >= 0
            ),
            key=lambda item: item[1],
        )
    ]
    return {
        "lifecycle_marker_order_expected": REQUIRED_LIFECYCLE_STEP_ORDER,
        "lifecycle_marker_order_actual": actual,
        "lifecycle_marker_order_positions": positions,
        "lifecycle_marker_order_missing": missing,
        "lifecycle_marker_order_position_count": len(
            [position for position in positions.values() if position >= 0]
        ),
        "lifecycle_marker_order_trace_ready": (
            not missing
            and actual == REQUIRED_LIFECYCLE_STEP_ORDER
        ),
        "lifecycle_marker_order_trace_claim_boundary": (
            LIFECYCLE_MARKER_ORDER_TRACE_CLAIM_BOUNDARY
        ),
    }


def _missing_decision_dimensions(text: str) -> list[str]:
    section = _markdown_section(text, "Senior Engineering Decision Trail")
    if section is None:
        return REQUIRED_DECISION_DIMENSIONS.copy()
    return [
        dimension
        for dimension in REQUIRED_DECISION_DIMENSIONS
        if f"- {dimension}:" not in section
    ]


def _missing_lifecycle_markers(text: str) -> list[str]:
    section = _markdown_section(text, "Scenario Lifecycle Trail")
    if section is None:
        return REQUIRED_LIFECYCLE_MARKERS + REQUIRED_RESEARCH_PERSPECTIVES
    lower_section = section.lower()
    missing = [
        marker
        for marker in REQUIRED_LIFECYCLE_MARKERS
        if marker != "## Scenario Lifecycle Trail" and f"- {marker}:" not in section
    ]
    missing.extend(
        perspective
        for perspective in REQUIRED_RESEARCH_PERSPECTIVES
        if perspective.lower() not in lower_section
    )
    return missing


def _delivery_unit_closure_flags(text: str) -> dict[str, bool]:
    lifecycle_section = _markdown_section(text, "Scenario Lifecycle Trail") or ""
    lower_lifecycle = lifecycle_section.lower()
    return {
        "decision_trail_complete": not _missing_decision_dimensions(text),
        "lifecycle_trail_complete": not _missing_lifecycle_markers(text),
        "research_perspectives_complete": all(
            perspective in lower_lifecycle
            for perspective in REQUIRED_RESEARCH_PERSPECTIVES
        ),
        "implementation_approach_defined": "- Implementation approach:" in lifecycle_section,
        "smallest_complete_solution_documented": "- Smallest complete solution:" in lifecycle_section,
        "refactor_and_hardening_documented": "- Refactor and hardening:" in lifecycle_section,
        "verification_result_documented": "- Verification result:" in lifecycle_section,
        "documented_result_present": "- Documented result:" in lifecycle_section,
        "connectorhub_adoption_contribution_documented": (
            "- ConnectorHub adoption contribution:" in lifecycle_section
        ),
    }


def _delivery_unit_coverage_facts(text: str) -> dict[str, object]:
    decision_section = _markdown_section(text, "Senior Engineering Decision Trail") or ""
    lifecycle_section = _markdown_section(text, "Scenario Lifecycle Trail")
    lower_lifecycle = (lifecycle_section or "").lower()
    lifecycle_value_markers = [
        marker
        for marker in REQUIRED_LIFECYCLE_MARKERS
        if marker != "## Scenario Lifecycle Trail"
    ]
    decision_dimension_values = _markdown_bullet_values(
        decision_section,
        REQUIRED_DECISION_DIMENSIONS,
    )
    lifecycle_marker_values = _markdown_bullet_values(
        lifecycle_section or "",
        lifecycle_value_markers,
    )
    lifecycle_order_facts = _lifecycle_marker_order_facts(lifecycle_section)
    completion_method_values = {
        marker: lifecycle_marker_values.get(marker, "")
        for marker in COMPLETION_METHOD_MARKERS
    }
    decision_dimension_value_lengths = {
        dimension: len(value)
        for dimension, value in decision_dimension_values.items()
    }
    lifecycle_marker_value_lengths = {
        marker: len(value)
        for marker, value in lifecycle_marker_values.items()
    }
    decision_dimensions_with_insufficient_detail = [
        dimension
        for dimension, length in decision_dimension_value_lengths.items()
        if length < MIN_DECISION_TRAIL_VALUE_CHARS
    ]
    lifecycle_markers_with_insufficient_detail = [
        marker
        for marker, length in lifecycle_marker_value_lengths.items()
        if length < MIN_LIFECYCLE_TRAIL_VALUE_CHARS
    ]
    completion_method_value_lengths = {
        marker: len(value)
        for marker, value in completion_method_values.items()
    }
    completion_method_markers_missing = [
        marker
        for marker in COMPLETION_METHOD_MARKERS
        if not completion_method_values.get(marker)
    ]
    completion_method_markers_with_insufficient_detail = [
        marker
        for marker, length in completion_method_value_lengths.items()
        if length < MIN_LIFECYCLE_TRAIL_VALUE_CHARS
    ]

    decision_dimensions_present = [
        dimension
        for dimension in REQUIRED_DECISION_DIMENSIONS
        if f"- {dimension}:" in decision_section
    ]
    lifecycle_markers_present = [
        marker
        for marker in REQUIRED_LIFECYCLE_MARKERS
        if (
            marker == "## Scenario Lifecycle Trail"
            and lifecycle_section is not None
        )
        or (
            marker != "## Scenario Lifecycle Trail"
            and lifecycle_section is not None
            and f"- {marker}:" in lifecycle_section
        )
    ]
    research_perspectives_present = [
        perspective
        for perspective in REQUIRED_RESEARCH_PERSPECTIVES
        if perspective.lower() in lower_lifecycle
    ]
    research_perspective_text_source = lifecycle_marker_values.get(
        "Research perspectives",
        "",
    )
    research_perspective_text_values = {
        perspective: research_perspective_text_source
        for perspective in REQUIRED_RESEARCH_PERSPECTIVES
        if perspective in research_perspectives_present
    }
    research_perspective_text_missing = [
        perspective
        for perspective in REQUIRED_RESEARCH_PERSPECTIVES
        if perspective not in research_perspective_text_values
    ]
    research_perspective_text_value_lengths = {
        perspective: len(value)
        for perspective, value in research_perspective_text_values.items()
    }
    research_perspective_decision_bridge_values = {}
    for perspective in REQUIRED_RESEARCH_PERSPECTIVES:
        dimensions = RESEARCH_PERSPECTIVE_DECISION_DIMENSIONS[perspective]
        linked_values = {
            dimension: decision_dimension_values.get(dimension, "")
            for dimension in dimensions
        }
        linked_lengths = {
            dimension: len(value)
            for dimension, value in linked_values.items()
        }
        missing_dimensions = [
            dimension for dimension, value in linked_values.items() if not value
        ]
        insufficient_dimensions = [
            dimension
            for dimension, length in linked_lengths.items()
            if length < MIN_DECISION_TRAIL_VALUE_CHARS
        ]
        min_linked_chars = min(linked_lengths.values()) if linked_lengths else 0
        trace_ready = (
            perspective in research_perspectives_present
            and not missing_dimensions
            and not insufficient_dimensions
            and len(linked_values) == len(dimensions)
        )
        research_perspective_decision_bridge_values[perspective] = {
            "decision_dimensions": dimensions,
            "decision_dimension_count": len(dimensions),
            "missing_decision_dimensions": missing_dimensions,
            "insufficient_decision_dimensions": insufficient_dimensions,
            "min_decision_dimension_chars": min_linked_chars,
            "trace_ready": trace_ready,
            "claim_boundary": RESEARCH_PERSPECTIVE_DECISION_BRIDGE_CLAIM_BOUNDARY,
        }
    research_perspective_decision_bridge_missing = [
        perspective
        for perspective, value in research_perspective_decision_bridge_values.items()
        if not value["trace_ready"]
    ]
    research_perspective_decision_bridge_min_chars = min(
        (
            value["min_decision_dimension_chars"]
            for value in research_perspective_decision_bridge_values.values()
        ),
        default=0,
    )

    return {
        "decision_dimensions_present": decision_dimensions_present,
        "decision_dimensions_present_count": len(decision_dimensions_present),
        "decision_dimensions_missing": [
            dimension
            for dimension in REQUIRED_DECISION_DIMENSIONS
            if dimension not in decision_dimensions_present
        ],
        "decision_dimension_values": decision_dimension_values,
        "decision_dimension_value_lengths": decision_dimension_value_lengths,
        "decision_dimension_value_min_length": (
            min(decision_dimension_value_lengths.values())
            if decision_dimension_value_lengths
            else 0
        ),
        "decision_dimension_value_min_required": MIN_DECISION_TRAIL_VALUE_CHARS,
        "decision_dimensions_with_insufficient_detail": decision_dimensions_with_insufficient_detail,
        "decision_dimensions_substantive": (
            not decision_dimensions_with_insufficient_detail
            and len(decision_dimension_values) == len(REQUIRED_DECISION_DIMENSIONS)
        ),
        "decision_dimension_text_trace_ready": (
            not decision_dimensions_with_insufficient_detail
            and len(decision_dimension_values) == len(REQUIRED_DECISION_DIMENSIONS)
        ),
        "decision_dimension_text_trace_claim_boundary": (
            DECISION_DIMENSION_TEXT_TRACE_CLAIM_BOUNDARY
        ),
        "research_perspectives_present": research_perspectives_present,
        "research_perspectives_present_count": len(research_perspectives_present),
        "research_perspectives_missing": [
            perspective
            for perspective in REQUIRED_RESEARCH_PERSPECTIVES
            if perspective not in research_perspectives_present
        ],
        "research_perspective_text_values": research_perspective_text_values,
        "research_perspective_text_value_lengths": research_perspective_text_value_lengths,
        "research_perspective_text_value_min_length": (
            min(research_perspective_text_value_lengths.values())
            if research_perspective_text_value_lengths
            else 0
        ),
        "research_perspective_text_missing": research_perspective_text_missing,
        "research_perspective_text_trace_ready": (
            not research_perspective_text_missing
            and len(research_perspective_text_values) == len(REQUIRED_RESEARCH_PERSPECTIVES)
            and (
                min(research_perspective_text_value_lengths.values())
                if research_perspective_text_value_lengths
                else 0
            ) >= MIN_LIFECYCLE_TRAIL_VALUE_CHARS
        ),
        "research_perspective_text_trace_claim_boundary": (
            RESEARCH_PERSPECTIVE_TEXT_TRACE_CLAIM_BOUNDARY
        ),
        "research_perspective_decision_bridge_values": research_perspective_decision_bridge_values,
        "research_perspective_decision_bridge_missing": (
            research_perspective_decision_bridge_missing
        ),
        "research_perspective_decision_bridge_min_chars": (
            research_perspective_decision_bridge_min_chars
        ),
        "research_perspective_decision_bridge_trace_ready": (
            not research_perspective_decision_bridge_missing
            and len(research_perspective_decision_bridge_values)
            == len(REQUIRED_RESEARCH_PERSPECTIVES)
        ),
        "research_perspective_decision_bridge_claim_boundary": (
            RESEARCH_PERSPECTIVE_DECISION_BRIDGE_CLAIM_BOUNDARY
        ),
        "lifecycle_markers_present": lifecycle_markers_present,
        "lifecycle_markers_present_count": len(lifecycle_markers_present),
        "lifecycle_markers_missing": [
            marker
            for marker in REQUIRED_LIFECYCLE_MARKERS
            if marker not in lifecycle_markers_present
        ],
        "lifecycle_marker_values": lifecycle_marker_values,
        "lifecycle_marker_value_lengths": lifecycle_marker_value_lengths,
        "lifecycle_marker_value_min_length": (
            min(lifecycle_marker_value_lengths.values())
            if lifecycle_marker_value_lengths
            else 0
        ),
        "lifecycle_marker_value_min_required": MIN_LIFECYCLE_TRAIL_VALUE_CHARS,
        "lifecycle_markers_with_insufficient_detail": lifecycle_markers_with_insufficient_detail,
        "lifecycle_markers_substantive": (
            not lifecycle_markers_with_insufficient_detail
            and len(lifecycle_marker_values) == len(lifecycle_value_markers)
        ),
        "lifecycle_marker_text_trace_ready": (
            not lifecycle_markers_with_insufficient_detail
            and len(lifecycle_marker_values) == len(lifecycle_value_markers)
        ),
        "lifecycle_marker_text_trace_claim_boundary": (
            LIFECYCLE_MARKER_TEXT_TRACE_CLAIM_BOUNDARY
        ),
        **lifecycle_order_facts,
        "completion_method_values": completion_method_values,
        "completion_method_value_lengths": completion_method_value_lengths,
        "completion_method_value_min_length": (
            min(completion_method_value_lengths.values())
            if completion_method_value_lengths
            else 0
        ),
        "completion_method_markers_missing": completion_method_markers_missing,
        "completion_method_markers_with_insufficient_detail": (
            completion_method_markers_with_insufficient_detail
        ),
        "completion_method_trace_ready": (
            not completion_method_markers_missing
            and not completion_method_markers_with_insufficient_detail
        ),
        "completion_method_trace_claim_boundary": COMPLETION_METHOD_TRACE_CLAIM_BOUNDARY,
    }


def _decision_rationale_trace_facts(
    text: str,
    row: dict[str, str],
) -> dict[str, object]:
    decision_section = _markdown_section(text, "Senior Engineering Decision Trail") or ""
    anchor_values = {
        "scenario_id": row["scenario_id"],
        "scenario_title": row["title"],
        "expected_result": row["expected_result"],
        "verification_method": row["verification_method"],
        "proof_surface": f"proof_surface={row['proof_surface']}",
        "claim_boundary": row["claim_boundary"],
        "evidence_report": row["evidence_required"],
        "independent_delivery_unit": "independent delivery unit",
        "connectorhub_adoption": "Connector Hub adoption",
    }
    missing = [
        label
        for label, value in anchor_values.items()
        if value not in decision_section
    ]
    return {
        "decision_rationale_anchor_labels": DECISION_RATIONALE_ANCHORS,
        "decision_rationale_anchor_count": len(anchor_values) - len(missing),
        "decision_rationale_anchors_missing": missing,
        "decision_rationale_trace_ready": bool(decision_section) and not missing,
        "decision_rationale_trace_claim_boundary": DECISION_RATIONALE_TRACE_CLAIM_BOUNDARY,
    }


def _focused_report_delivery_facts(report_path: Path) -> dict[str, object]:
    if not report_path.exists():
        return {
            "focused_report_present": False,
            "focused_report_status": None,
            "focused_report_scenario_count": 0,
            "focused_report_pass": 0,
            "focused_report_blocking": 0,
            "focused_report_human_required": None,
            "focused_report_not_verified": None,
            "focused_report_evidence_trail_ready": False,
            "focused_report_evidence_item_count": 0,
            "focused_report_evidence_items": [],
            "focused_report_command_evidence_count": 0,
            "focused_report_command_evidence_schema_valid_count": 0,
            "focused_report_command_evidence_schema_invalid_count": 0,
            "focused_report_command_evidence_exit_code_counts": {},
            "focused_report_negative_evidence_count": 0,
            "focused_report_negative_evidence_all_zero": False,
            "focused_report_self_command_transcript_present": False,
            "focused_report_self_command_transcript_exit_code": None,
            "focused_report_source_state_git_commit_present": False,
            "focused_report_command_evidence_has_audit_command": False,
            "focused_report_object_or_static_state_evidence_present": False,
            "focused_report_top_level_audit_ref_count": 0,
            "focused_report_top_level_evidence_ref_count": 0,
            "focused_report_top_level_policy_decision_ref_count": 0,
            "focused_report_embedded_audit_ref_count": 0,
            "focused_report_embedded_evidence_ref_count": 0,
            "focused_report_embedded_policy_decision_ref_count": 0,
            "focused_report_embedded_audit_refs_present": False,
            "focused_report_embedded_evidence_refs_present": False,
            "focused_report_embedded_policy_decision_refs_present": False,
            "focused_report_embedded_state_or_audit_object_count": 0,
            "focused_report_embedded_state_or_audit_object_present": False,
            "focused_report_error_count": 0,
            "focused_report_failure_analysis_not_applicable": False,
            "focused_report_readiness_dimension_counts": {},
        }
    payload = _load_connector_contract_report(report_path)
    summary = payload.get("summary", {})
    scenario_results = payload.get("scenario_results") or []
    result = scenario_results[0] if len(scenario_results) == 1 and isinstance(scenario_results[0], dict) else {}
    evidence_items = result.get("evidence") if isinstance(result.get("evidence"), list) else []
    command_evidence = payload.get("command_evidence") if isinstance(payload.get("command_evidence"), list) else []
    command_evidence_schema_valid_count = sum(
        1
        for item in command_evidence
        if isinstance(item, dict)
        and item.get("schema_version") == "cs.cli_transcript.v0"
        and isinstance(item.get("command"), list)
    )
    command_evidence_exit_code_counts = Counter(
        str(item.get("exit_code"))
        for item in command_evidence
        if isinstance(item, dict)
    )
    negative_evidence = payload.get("negative_evidence") if isinstance(payload.get("negative_evidence"), dict) else {}
    negative_evidence_all_zero = bool(negative_evidence) and all(
        value in (0, False, None) or value == [] or value == {}
        for value in negative_evidence.values()
    )
    self_command_transcript = (
        payload.get("self_command_transcript")
        if isinstance(payload.get("self_command_transcript"), dict)
        else {}
    )
    ids = payload.get("ids") if isinstance(payload.get("ids"), dict) else {}
    audit_refs = payload.get("audit_refs") if isinstance(payload.get("audit_refs"), list) else []
    evidence_refs = (
        payload.get("evidence_refs")
        if isinstance(payload.get("evidence_refs"), list)
        else []
    )
    policy_decision_refs = (
        payload.get("policy_decision_refs")
        if isinstance(payload.get("policy_decision_refs"), list)
        else []
    )
    errors = payload.get("errors") if isinstance(payload.get("errors"), list) else []
    command_stdout_jsons = [
        item.get("stdout_json")
        for item in command_evidence
        if isinstance(item, dict)
        and isinstance(item.get("stdout_json"), dict)
    ]
    embedded_audit_ref_count = sum(
        len(stdout_json.get("audit_refs"))
        for stdout_json in command_stdout_jsons
        if isinstance(stdout_json.get("audit_refs"), list)
    )
    embedded_evidence_ref_count = sum(
        len(stdout_json.get("evidence_refs"))
        for stdout_json in command_stdout_jsons
        if isinstance(stdout_json.get("evidence_refs"), list)
    )
    embedded_policy_decision_ref_count = sum(
        len(stdout_json.get("policy_decision_refs"))
        for stdout_json in command_stdout_jsons
        if isinstance(stdout_json.get("policy_decision_refs"), list)
    )
    embedded_state_or_audit_object_count = sum(
        1
        for stdout_json in command_stdout_jsons
        if any(
            key.endswith("_state")
            or key.endswith("_audit")
            or key == "connector_product_surface_audit"
            for key in stdout_json
        )
    )
    command_evidence_has_audit_command = any(
        isinstance(item, dict)
        and any("audit" in str(part).lower() for part in item.get("command", []))
        for item in command_evidence
    )
    object_or_static_state_evidence_present = any(
        isinstance(item, str)
        and (
            item.startswith("tmp/")
            or item.endswith(".json")
            or "scan" in item.lower()
        )
        for item in evidence_items
    ) or embedded_state_or_audit_object_count > 0
    failure_analysis_not_applicable = (
        summary.get("fail") == 0
        and summary.get("blocking") == 0
        and summary.get("not_verified") == 0
        and len(errors) == 0
    )
    readiness_dimensions = (
        payload.get("readiness_dimensions")
        if isinstance(payload.get("readiness_dimensions"), dict)
        else {}
    )
    readiness_dimension_counts = Counter(str(value) for value in readiness_dimensions.values())
    focused_report_evidence_trail_ready = (
        bool(evidence_items)
        and command_evidence_schema_valid_count == len(command_evidence)
        and len(command_evidence) > 0
        and negative_evidence_all_zero
        and self_command_transcript.get("schema_version") == "cs.command_transcript.v0"
        and self_command_transcript.get("exit_code") == 0
        and readiness_dimension_counts == Counter(
            {
                "LOCAL_FIXTURE_VERIFIED": 2,
                "HUMAN_REQUIRED": 2,
                "NOT_VERIFIED": 3,
                "OUT_OF_SCOPE_READ_ONLY": 1,
            }
        )
    )
    return {
        "focused_report_present": True,
        "focused_report_status": payload.get("status"),
        "focused_report_scenario_count": summary.get("scenario_count"),
        "focused_report_pass": summary.get("pass"),
        "focused_report_blocking": summary.get("blocking"),
        "focused_report_human_required": summary.get("human_required"),
        "focused_report_not_verified": summary.get("not_verified"),
        "focused_report_evidence_trail_ready": focused_report_evidence_trail_ready,
        "focused_report_evidence_item_count": len(evidence_items),
        "focused_report_evidence_items": evidence_items,
        "focused_report_command_evidence_count": len(command_evidence),
        "focused_report_command_evidence_schema_valid_count": command_evidence_schema_valid_count,
        "focused_report_command_evidence_schema_invalid_count": (
            len(command_evidence) - command_evidence_schema_valid_count
        ),
        "focused_report_command_evidence_exit_code_counts": dict(sorted(command_evidence_exit_code_counts.items())),
        "focused_report_negative_evidence_count": len(negative_evidence),
        "focused_report_negative_evidence_all_zero": negative_evidence_all_zero,
        "focused_report_self_command_transcript_present": bool(self_command_transcript),
        "focused_report_self_command_transcript_exit_code": self_command_transcript.get("exit_code"),
        "focused_report_source_state_git_commit_present": bool(ids.get("git_commit")),
        "focused_report_command_evidence_has_audit_command": command_evidence_has_audit_command,
        "focused_report_object_or_static_state_evidence_present": (
            object_or_static_state_evidence_present
        ),
        "focused_report_top_level_audit_ref_count": len(audit_refs),
        "focused_report_top_level_evidence_ref_count": len(evidence_refs),
        "focused_report_top_level_policy_decision_ref_count": len(policy_decision_refs),
        "focused_report_embedded_audit_ref_count": embedded_audit_ref_count,
        "focused_report_embedded_evidence_ref_count": embedded_evidence_ref_count,
        "focused_report_embedded_policy_decision_ref_count": (
            embedded_policy_decision_ref_count
        ),
        "focused_report_embedded_audit_refs_present": embedded_audit_ref_count > 0,
        "focused_report_embedded_evidence_refs_present": (
            embedded_evidence_ref_count > 0
        ),
        "focused_report_embedded_policy_decision_refs_present": (
            embedded_policy_decision_ref_count > 0
        ),
        "focused_report_embedded_state_or_audit_object_count": (
            embedded_state_or_audit_object_count
        ),
        "focused_report_embedded_state_or_audit_object_present": (
            embedded_state_or_audit_object_count > 0
        ),
        "focused_report_error_count": len(errors),
        "focused_report_failure_analysis_not_applicable": failure_analysis_not_applicable,
        "focused_report_readiness_dimensions": dict(sorted(readiness_dimensions.items())),
        "focused_report_readiness_dimension_counts": dict(sorted(readiness_dimension_counts.items())),
    }


def _focused_gate_delivery_facts(report_path: Path) -> dict[str, object]:
    if not report_path.exists() or not CORNERSTONE_CLI_PATH.exists():
        return {
            "focused_gate_present": False,
            "focused_gate_status": None,
            "focused_gate_scenario_count": 0,
            "focused_gate_blocking_count": None,
            "focused_gate_error_count": None,
            "focused_gate_checked_report": None,
        }
    relative_report_path = report_path.resolve().relative_to(ROOT.resolve()).as_posix()
    command = [
        str(CORNERSTONE_CLI_PATH),
        "scenario",
        "gate",
        relative_report_path,
        "--json",
    ]
    try:
        result = subprocess.run(
            command,
            cwd=ROOT,
            check=False,
            capture_output=True,
            text=True,
            timeout=30,
        )
    except subprocess.TimeoutExpired:
        return {
            "focused_gate_present": False,
            "focused_gate_status": "timeout",
            "focused_gate_scenario_count": 0,
            "focused_gate_blocking_count": None,
            "focused_gate_error_count": None,
            "focused_gate_checked_report": relative_report_path,
        }
    if result.returncode != 0:
        return {
            "focused_gate_present": False,
            "focused_gate_status": "command_failed",
            "focused_gate_scenario_count": 0,
            "focused_gate_blocking_count": None,
            "focused_gate_error_count": None,
            "focused_gate_checked_report": relative_report_path,
        }
    try:
        payload = json.loads(result.stdout)
    except json.JSONDecodeError:
        return {
            "focused_gate_present": False,
            "focused_gate_status": "invalid_json",
            "focused_gate_scenario_count": 0,
            "focused_gate_blocking_count": None,
            "focused_gate_error_count": None,
            "focused_gate_checked_report": relative_report_path,
        }
    return {
        "focused_gate_present": True,
        "focused_gate_status": payload.get("status"),
        "focused_gate_scenario_count": payload.get("scenario_count"),
        "focused_gate_blocking_count": payload.get("blocking_count"),
        "focused_gate_error_count": len(payload.get("errors") or []),
        "focused_gate_checked_report": relative_report_path,
    }


def _expand_source_scenario_expression(value: str) -> list[str]:
    scenario_ids: list[str] = []
    for token in [item.strip() for item in value.split(",") if item.strip()]:
        range_match = re.fullmatch(r"CS-CH-(\d{3})-(\d{3})", token)
        if range_match:
            start = int(range_match.group(1))
            end = int(range_match.group(2))
            scenario_ids.extend(
                f"CS-CH-{number:03d}"
                for number in range(start, end + 1)
            )
            continue
        if re.fullmatch(r"CS-CH-(?:\d{3}|H\d{2})", token):
            scenario_ids.append(token)
    return scenario_ids


def _source_implementation_batch_records() -> list[dict[str, object]]:
    source_path = SOURCE_INPUTS[1]["path"]
    records = []
    for line_number, line in enumerate(source_path.read_text().splitlines(), 1):
        if line_number < SOURCE_IMPLEMENTATION_BATCH_ROW_START:
            continue
        if line_number > SOURCE_IMPLEMENTATION_BATCH_ROW_END:
            break
        if not line.startswith("| CH-"):
            continue
        cells = [cell.strip() for cell in line.strip().strip("|").split("|")]
        if len(cells) != 4:
            continue
        batch_label, source_scenarios, source_deliverable, source_release_posture = cells
        phase_match = re.match(r"(?P<phase>CH-\d+)\s+-\s+(?P<name>.+)", batch_label)
        if phase_match:
            phase = phase_match.group("phase")
            source_name = phase_match.group("name")
        else:
            phase = batch_label
            source_name = batch_label
        records.append(
            {
                "phase": phase,
                "source_batch_label": batch_label,
                "source_batch_name": source_name,
                "source_scenario_expression": source_scenarios,
                "source_scenario_ids": _expand_source_scenario_expression(source_scenarios),
                "source_deliverable": source_deliverable,
                "source_release_posture": source_release_posture,
                "source_line": line_number,
                "source_ref": f"Implementation document line {line_number}",
                "source_line_range": SOURCE_IMPLEMENTATION_BATCH_SOURCE_REF,
                "claim_boundary": SOURCE_IMPLEMENTATION_BATCH_CLAIM_BOUNDARY,
            }
        )
    return records


def _source_implementation_batches(
    matrix_rows: list[dict[str, str]],
) -> list[dict[str, object]]:
    implementation_plan_by_phase = {
        item["phase"]: item for item in IMPLEMENTATION_PHASE_PLAN
    }
    matrix_ai_by_phase: dict[str, list[str]] = {
        phase: sorted(
            row["scenario_id"]
            for row in matrix_rows
            if row.get("phase") == phase
            and row.get("owner") == "AI"
            and row.get("status") == "PASS"
        )
        for phase in EXPECTED_MATRIX_PHASES
    }
    rows = []
    for source_batch in _source_implementation_batch_records():
        phase = str(source_batch["phase"])
        plan_row = implementation_plan_by_phase.get(phase)
        matrix_ai_ids = matrix_ai_by_phase.get(phase, [])
        plan_ai_ids = plan_row["ai_scenario_ids"] if plan_row else []
        source_scenario_ids = list(source_batch["source_scenario_ids"])
        matrix_scenarios_match_source_batch = matrix_ai_ids == source_scenario_ids
        implementation_plan_scenarios_match_source_batch = (
            plan_ai_ids == source_scenario_ids
        )
        trace_ready = (
            plan_row is not None
            and matrix_scenarios_match_source_batch
            and implementation_plan_scenarios_match_source_batch
        )
        operator_handoff_ready = (
            trace_ready
            and bool(source_scenario_ids)
            and bool(source_batch["source_deliverable"])
            and bool(source_batch["source_release_posture"])
        )
        implementation_plan_name = plan_row["name"] if plan_row else None
        implementation_phase_name_matches_source = (
            implementation_plan_name == source_batch["source_batch_name"]
        )
        phase_name_override = SOURCE_IMPLEMENTATION_BATCH_PHASE_NAME_OVERRIDES.get(
            phase
        )
        phase_name_override_applied = bool(
            phase_name_override
            and source_batch["source_batch_name"]
            in phase_name_override["source_batch_names"]
            and implementation_plan_name == phase_name_override["implementation_plan_name"]
        )
        rows.append(
            {
                **source_batch,
                "matrix_ai_scenario_ids": matrix_ai_ids,
                "matrix_ai_scenario_count": len(matrix_ai_ids),
                "implementation_plan_present": plan_row is not None,
                "implementation_plan_name": implementation_plan_name,
                "implementation_plan_scenario_ids": plan_ai_ids,
                "matrix_scenarios_match_source_batch": matrix_scenarios_match_source_batch,
                "implementation_plan_scenarios_match_source_batch": (
                    implementation_plan_scenarios_match_source_batch
                ),
                "implementation_phase_name_matches_source": (
                    implementation_phase_name_matches_source
                ),
                "implementation_phase_name_override_applied": (
                    phase_name_override_applied
                ),
                "implementation_phase_name_override_rationale": (
                    phase_name_override["rationale"]
                    if phase_name_override_applied
                    else None
                ),
                "implementation_phase_name_override_source_refs": (
                    list(phase_name_override["source_refs"])
                    if phase_name_override_applied
                    else []
                ),
                "implementation_phase_name_override_claim_boundary": (
                    phase_name_override["claim_boundary"]
                    if phase_name_override_applied
                    else None
                ),
                "operator_handoff_ready": operator_handoff_ready,
                "runtime_claim_allowed": False,
                "release_claim_allowed": False,
                "human_acceptance_claim_allowed": False,
                "completion_claim_allowed": False,
                "completion_blocked_until_phase_evidence": True,
                "trace_ready": trace_ready,
            }
        )
    return rows


def _implementation_phase_plan(matrix_rows: list[dict[str, str]]) -> list[dict[str, object]]:
    ai_by_phase: dict[str, list[str]] = {
        phase: sorted(
            row["scenario_id"]
            for row in matrix_rows
            if row.get("phase") == phase
            and row.get("owner") == "AI"
            and row.get("status") == "PASS"
        )
        for phase in EXPECTED_MATRIX_PHASES
    }
    human_by_phase: dict[str, list[str]] = {
        phase: sorted(
            row["scenario_id"]
            for row in matrix_rows
            if row.get("phase") == phase
            and row.get("owner") == "Human"
            and row.get("status") == "HUMAN_REQUIRED"
        )
        for phase in EXPECTED_MATRIX_PHASES
    }
    plan = []
    for index, phase_plan in enumerate(IMPLEMENTATION_PHASE_PLAN, start=1):
        phase = phase_plan["phase"]
        observed_ai_ids = ai_by_phase.get(phase, [])
        expected_ai_ids = phase_plan["ai_scenario_ids"]
        human_gate_ids = human_by_phase.get(phase, [])
        trace_ready = observed_ai_ids == expected_ai_ids
        operator_handoff_ready = (
            trace_ready
            and bool(phase_plan["source_refs"])
            and bool(phase_plan["smallest_valuable_deliverable"])
            and bool(phase_plan["release_posture"])
            and bool(phase_plan["native_verifier_command"])
        )
        plan.append(
            {
                "sequence_index": index,
                "phase": phase,
                "name": phase_plan["name"],
                "source_scenario_set": phase_plan["source_scenario_set"],
                "source_refs": phase_plan["source_refs"],
                "smallest_valuable_deliverable": phase_plan["smallest_valuable_deliverable"],
                "release_posture": phase_plan["release_posture"],
                "native_verifier_command": phase_plan["native_verifier_command"],
                "expected_ai_scenario_ids": expected_ai_ids,
                "observed_ai_delivery_unit_ids": observed_ai_ids,
                "observed_ai_delivery_unit_count": len(observed_ai_ids),
                "ai_scenario_ids_match_source_plan": trace_ready,
                "human_required_gate_ids": human_gate_ids,
                "human_required_gate_count": len(human_gate_ids),
                "human_required_gate_claim_boundary": "human_required_gates_remain_outside_ai_local_pass",
                "operator_handoff_ready": operator_handoff_ready,
                "runtime_claim_allowed": False,
                "release_claim_allowed": False,
                "human_acceptance_claim_allowed": False,
                "completion_claim_allowed": False,
                "completion_blocked_until_phase_evidence": True,
                "trace_ready": trace_ready,
                "phase_claim_boundary": IMPLEMENTATION_PHASE_PLAN_CLAIM_BOUNDARY,
            }
        )
    return plan


