def _source_open_question_trace() -> list[dict[str, object]]:
    open_question_section = next(
        section
        for section in SOURCE_VERIFICATION_PLAN_SECTIONS
        if section["section_id"] == "open_questions"
    )
    rows = []
    for index, question in enumerate(open_question_section["items"], start=1):
        requirement = SOURCE_OPEN_QUESTION_DECISION_REQUIREMENTS[question]
        related_human_gate_ids = list(requirement["related_human_gate_ids"])
        next_operator_human_gate_id = next(
            (
                scenario_id
                for scenario_id in EXPECTED_HUMAN_GATE_EXECUTION_ORDER
                if scenario_id in related_human_gate_ids
            ),
            None,
        )
        rows.append(
            {
                "question_index": index,
                "question": question,
                "source_ref": open_question_section["source_ref"],
                "decision_status": requirement["decision_status"],
                "required_decision_artifact": requirement["required_decision_artifact"],
                "related_human_gate_ids": related_human_gate_ids,
                "related_human_gate_count": len(related_human_gate_ids),
                "next_operator_human_gate_id": next_operator_human_gate_id,
                "next_operator_package_command": (
                    f"cornerstone connector human-gate package --scenario "
                    f"{next_operator_human_gate_id} --json"
                    if next_operator_human_gate_id
                    else None
                ),
                "next_operator_record_template_command": (
                    f"cornerstone connector human-gate package --scenario "
                    f"{next_operator_human_gate_id} --json "
                    "--record-template-output <reviewer-record-template.json>"
                    if next_operator_human_gate_id
                    else None
                ),
                "next_operator_validation_output_command": (
                    f"cornerstone connector human-gate validate-record --scenario "
                    f"{next_operator_human_gate_id} --record-file <json> --json "
                    "--output <redacted-validation-envelope.json>"
                    if next_operator_human_gate_id
                    else None
                ),
                "required_proof_surfaces": list(requirement["required_proof_surfaces"]),
                "required_proof_surface_count": len(requirement["required_proof_surfaces"]),
                "required_evidence": list(requirement["required_evidence"]),
                "required_evidence_count": len(requirement["required_evidence"]),
                "decision_resolved": False,
                "operator_handoff_ready": bool(next_operator_human_gate_id),
                "completion_blocked_until_human_accept": True,
                "acceptance_claim_allowed": False,
                "trace_ready": (
                    bool(requirement["decision_status"])
                    and bool(requirement["required_decision_artifact"])
                    and bool(next_operator_human_gate_id)
                    and bool(requirement["required_proof_surfaces"])
                    and bool(requirement["required_evidence"])
                ),
                "claim_boundary": SOURCE_OPEN_QUESTION_TRACE_CLAIM_BOUNDARY,
            }
        )
    return rows


