def _source_initial_scenario_rows(
    matrix_rows: list[dict[str, str]],
) -> list[dict[str, object]]:
    matrix_by_id = {row["scenario_id"]: row for row in matrix_rows}
    source_rows = []
    for source_row in _source_initial_scenario_source_records():
        scenario_id = str(source_row["scenario_id"])
        row = matrix_by_id.get(scenario_id)
        matrix_row_present = row is not None
        source_type = str(source_row["source_type"])
        expected_matrix_type = SOURCE_INITIAL_SCENARIO_SOURCE_TYPE_TO_MATRIX_TYPE.get(
            source_type
        )
        matrix_type = row["type"] if matrix_row_present else None
        matrix_owner = row["owner"] if matrix_row_present else None
        matrix_status = row["status"] if matrix_row_present else None
        matrix_phase = row["phase"] if matrix_row_present else None
        matrix_requirement_ids = (
            _requirement_ids(row["related_requirements"])
            if matrix_row_present
            else []
        )
        source_requirement_ids = list(source_row["source_requirement_ids"])
        source_type_matches_current_matrix = (
            matrix_row_present and matrix_type == expected_matrix_type
        )
        type_escalation_override = SOURCE_TYPE_ESCALATION_OVERRIDES.get(scenario_id)
        type_escalation_override_applied = bool(
            type_escalation_override
            and source_type in type_escalation_override["source_types"]
            and matrix_type == type_escalation_override["matrix_type"]
        )
        source_requirements_match_current_matrix = (
            sorted(source_requirement_ids) == sorted(matrix_requirement_ids)
        )
        requirement_enrichment_override = SOURCE_REQUIREMENT_ENRICHMENT_OVERRIDES.get(
            scenario_id
        )
        added_requirement_ids = sorted(
            set(matrix_requirement_ids) - set(source_requirement_ids)
        )
        requirement_enrichment_override_applied = bool(
            requirement_enrichment_override
            and added_requirement_ids == requirement_enrichment_override["added_requirement_ids"]
            and sorted(source_requirement_ids)
            == sorted(set(matrix_requirement_ids) - set(added_requirement_ids))
        )
        if source_type == "HUMAN_REQUIRED":
            expected_owner_status = "Human/HUMAN_REQUIRED"
            status_boundary_ready = (
                matrix_owner == "Human" and matrix_status == "HUMAN_REQUIRED"
            )
        else:
            expected_owner_status = "AI/PASS"
            status_boundary_ready = matrix_owner == "AI" and matrix_status == "PASS"
        source_rows.append(
            {
                **source_row,
                "source_line_range": SOURCE_INITIAL_SCENARIO_ROW_SOURCE_REF,
                "matrix_row_present": matrix_row_present,
                "expected_matrix_type": expected_matrix_type,
                "matrix_type": matrix_type,
                "matrix_owner": matrix_owner,
                "matrix_status": matrix_status,
                "matrix_owner_status": (
                    f"{matrix_owner}/{matrix_status}"
                    if matrix_owner is not None and matrix_status is not None
                    else None
                ),
                "matrix_phase": matrix_phase,
                "matrix_requirement_ids": matrix_requirement_ids,
                "source_type_matches_current_matrix": source_type_matches_current_matrix,
                "type_escalation_override_applied": type_escalation_override_applied,
                "type_escalation_override_rationale": (
                    type_escalation_override["rationale"]
                    if type_escalation_override_applied
                    else None
                ),
                "type_escalation_override_source_refs": (
                    list(type_escalation_override["source_refs"])
                    if type_escalation_override_applied
                    else []
                ),
                "type_escalation_override_claim_boundary": (
                    type_escalation_override["claim_boundary"]
                    if type_escalation_override_applied
                    else None
                ),
                "source_requirements_match_current_matrix": (
                    source_requirements_match_current_matrix
                ),
                "requirement_enrichment_override_applied": (
                    requirement_enrichment_override_applied
                ),
                "requirement_enrichment_added_requirement_ids": (
                    added_requirement_ids
                    if requirement_enrichment_override_applied
                    else []
                ),
                "requirement_enrichment_override_rationale": (
                    requirement_enrichment_override["rationale"]
                    if requirement_enrichment_override_applied
                    else None
                ),
                "requirement_enrichment_override_source_refs": (
                    list(requirement_enrichment_override["source_refs"])
                    if requirement_enrichment_override_applied
                    else []
                ),
                "requirement_enrichment_override_claim_boundary": (
                    requirement_enrichment_override["claim_boundary"]
                    if requirement_enrichment_override_applied
                    else None
                ),
                "expected_owner_status": expected_owner_status,
                "status_boundary_ready": status_boundary_ready,
                "trace_ready": matrix_row_present and status_boundary_ready,
                "operator_handoff_ready": True,
                "source_row_pass_claim_allowed": False,
                "product_claim_allowed": False,
                "runtime_claim_allowed": False,
                "release_claim_allowed": False,
                "human_acceptance_claim_allowed": False,
                "completion_claim_allowed": False,
                "claim_boundary": SOURCE_INITIAL_SCENARIO_ROW_CLAIM_BOUNDARY,
            }
        )
    return source_rows


