def _source_human_required_checks(
    matrix_rows: list[dict[str, str]],
) -> list[dict[str, object]]:
    matrix_by_id = {row["scenario_id"]: row for row in matrix_rows}
    rows = []
    for source_row in _source_human_required_check_records():
        scenario_id = str(source_row["scenario_id"])
        row = matrix_by_id.get(scenario_id)
        matrix_row_present = row is not None
        matrix_type = row["type"] if matrix_row_present else None
        matrix_owner = row["owner"] if matrix_row_present else None
        matrix_status = row["status"] if matrix_row_present else None
        matrix_proof_surface = row["proof_surface"] if matrix_row_present else None
        matrix_claim_boundary = row["claim_boundary"] if matrix_row_present else ""
        package_path = HUMAN_GATE_PACKAGE_REPORT_PATHS.get(scenario_id)
        record_template_path = HUMAN_GATE_RECORD_TEMPLATE_PATHS.get(scenario_id)
        blank_validation_path = HUMAN_GATE_BLANK_VALIDATION_PATHS.get(scenario_id)
        review_template_path = _human_gate_review_template_path(scenario_id)
        matrix_boundary_ready = (
            matrix_type == "HUMAN_REQUIRED"
            and matrix_owner == "Human"
            and matrix_status == "HUMAN_REQUIRED"
            and matrix_proof_surface == "human_required"
            and "no AI PASS" in matrix_claim_boundary
        )
        package_present = bool(package_path and package_path.exists())
        record_template_present = bool(record_template_path and record_template_path.exists())
        blank_validation_present = bool(blank_validation_path and blank_validation_path.exists())
        review_template_present = review_template_path.exists()
        rows.append(
            {
                **source_row,
                "matrix_row_present": matrix_row_present,
                "matrix_type": matrix_type,
                "matrix_owner": matrix_owner,
                "matrix_status": matrix_status,
                "matrix_proof_surface": matrix_proof_surface,
                "matrix_claim_boundary": matrix_claim_boundary,
                "matrix_boundary_ready": matrix_boundary_ready,
                "package_path": (
                    package_path.relative_to(ROOT).as_posix()
                    if package_path is not None
                    else None
                ),
                "package_present": package_present,
                "record_template_path": (
                    record_template_path.relative_to(ROOT).as_posix()
                    if record_template_path is not None
                    else None
                ),
                "record_template_present": record_template_present,
                "blank_validation_path": (
                    blank_validation_path.relative_to(ROOT).as_posix()
                    if blank_validation_path is not None
                    else None
                ),
                "blank_validation_present": blank_validation_present,
                "review_template_path": review_template_path.relative_to(ROOT).as_posix(),
                "review_template_present": review_template_present,
                "trace_ready": (
                    matrix_boundary_ready
                    and bool(source_row["source_automation_gap"])
                    and bool(source_row["source_required_human_action"])
                    and bool(source_row["source_expected_evidence"])
                    and bool(source_row["source_release_impact"])
                    and package_present
                    and record_template_present
                    and blank_validation_present
                    and review_template_present
                ),
                "operator_handoff_ready": (
                    matrix_boundary_ready
                    and package_present
                    and record_template_present
                    and blank_validation_present
                    and review_template_present
                ),
                "product_claim_allowed": False,
                "pass_claim_allowed": False,
                "release_claim_allowed": False,
                "human_acceptance_claim_allowed": False,
                "completion_claim_allowed": False,
                "approval_collected": False,
                "human_acceptance_collected": False,
            }
        )
    return rows


def _human_required_work_mapping(
    human_rows: list[dict[str, str]],
) -> list[dict[str, object]]:
    source_check_by_id = {
        str(item["scenario_id"]): item
        for item in _source_human_required_check_records()
    }
    rows = []
    for row in human_rows:
        scenario_id = row["scenario_id"]
        source_check = source_check_by_id.get(scenario_id, {})
        why_ai_cannot_verify = source_check.get("source_automation_gap", "")
        required_human_action = source_check.get("source_required_human_action", "")
        expected_evidence_summary = source_check.get("source_expected_evidence", "")
        source_release_impact = source_check.get("source_release_impact", "")
        source_required_implementation = SCENARIO_REQUIRED_IMPLEMENTATIONS.get(
            scenario_id,
            "",
        )
        package_path = HUMAN_GATE_PACKAGE_REPORT_PATHS.get(scenario_id)
        record_template_path = HUMAN_GATE_RECORD_TEMPLATE_PATHS.get(scenario_id)
        blank_validation_path = HUMAN_GATE_BLANK_VALIDATION_PATHS.get(scenario_id)
        review_template_path = _human_gate_review_template_path(scenario_id)
        package_payload: dict[str, object] = {}
        package: dict[str, object] = {}
        if package_path is not None and package_path.exists():
            package_payload = json.loads(package_path.read_text())
            candidate_package = package_payload.get("connector_human_gate_package")
            if isinstance(candidate_package, dict):
                package = candidate_package
        required_human_record = package.get("required_human_record")
        if not isinstance(required_human_record, dict):
            required_human_record = {}
        required_human_fields = list(required_human_record.get("required_fields") or [])
        required_evidence = list(required_human_record.get("required_evidence") or [])
        proposed_template = package.get("proposed_record_template")
        if not isinstance(proposed_template, dict):
            proposed_template = {}
        scenario_delivery_unit_plan_summary = package.get(
            "scenario_delivery_unit_plan_summary"
        )
        if not isinstance(scenario_delivery_unit_plan_summary, dict):
            scenario_delivery_unit_plan_summary = {}
        source_requirement_ids = list(
            package.get("source_requirement_ids") or _requirement_ids(row["related_requirements"])
        )
        package_present = bool(package_path and package_path.exists())
        record_template_present = bool(record_template_path and record_template_path.exists())
        blank_validation_present = bool(blank_validation_path and blank_validation_path.exists())
        review_template_present = review_template_path.exists()
        record_template_output_command = proposed_template.get(
            "record_template_output_command"
        )
        validation_command = proposed_template.get("validation_command")
        validation_output_command = proposed_template.get("validation_output_command")
        product_claim_allowed = bool(
            proposed_template.get("product_claim_allowed_by_template")
            or scenario_delivery_unit_plan_summary.get(
                "scenario_delivery_unit_plan_product_claim_allowed"
            )
        )
        pass_claim_allowed = bool(
            proposed_template.get("pass_claim_allowed_by_template")
            or scenario_delivery_unit_plan_summary.get(
                "scenario_delivery_unit_plan_pass_claim_allowed"
            )
        )
        approval_collected = bool(
            scenario_delivery_unit_plan_summary.get(
                "scenario_delivery_unit_plan_approval_collected"
            )
        )
        trace_ready = (
            bool(source_required_implementation)
            and bool(why_ai_cannot_verify)
            and bool(required_human_action)
            and bool(expected_evidence_summary)
            and bool(source_release_impact)
            and package_present
            and record_template_present
            and blank_validation_present
            and review_template_present
            and bool(required_human_fields)
            and bool(required_evidence)
            and bool(record_template_output_command)
            and bool(validation_output_command)
            and not product_claim_allowed
            and not pass_claim_allowed
            and not approval_collected
        )
        rows.append(
            {
                "scenario_id": scenario_id,
                "phase": row["phase"],
                "title": package.get("title") or row["title"],
                "review_order": package.get("review_order"),
                "gate_category": package.get("gate_category"),
                "depends_on_human_gates": list(
                    package.get("depends_on_human_gates") or []
                ),
                "why_ai_cannot_verify": why_ai_cannot_verify,
                "required_human_action": required_human_action,
                "expected_evidence_summary": expected_evidence_summary,
                "source_release_impact": source_release_impact,
                "source_human_required_check_source_ref": source_check.get(
                    "source_ref"
                ),
                "stop_or_reject_when": package.get("stop_or_reject_when"),
                "release_impact": package.get("release_impact"),
                "source_required_implementation": source_required_implementation,
                "source_required_implementation_source_ref": (
                    SCENARIO_REQUIRED_IMPLEMENTATION_SOURCE_REF
                ),
                "source_required_implementation_trace_ready": bool(
                    source_required_implementation
                ),
                "source_required_implementation_operator_handoff_ready": bool(
                    source_required_implementation
                ),
                "source_required_implementation_completion_blocked_until_human_evidence": True,
                "source_required_implementation_pass_claim_allowed": False,
                "source_required_implementation_runtime_claim_allowed": False,
                "source_required_implementation_release_claim_allowed": False,
                "source_required_implementation_human_acceptance_claim_allowed": False,
                "source_requirement_ids": source_requirement_ids,
                "source_requirement_count": len(source_requirement_ids),
                "source_requirement_status": package.get("source_requirement_status"),
                "source_requirement_claim_boundary": package.get(
                    "source_requirement_claim_boundary"
                ),
                "package_path": (
                    package_path.relative_to(ROOT).as_posix()
                    if package_path is not None
                    else None
                ),
                "package_present": package_present,
                "record_template_path": (
                    record_template_path.relative_to(ROOT).as_posix()
                    if record_template_path is not None
                    else None
                ),
                "record_template_present": record_template_present,
                "blank_validation_path": (
                    blank_validation_path.relative_to(ROOT).as_posix()
                    if blank_validation_path is not None
                    else None
                ),
                "blank_validation_present": blank_validation_present,
                "review_template_path": review_template_path.relative_to(ROOT).as_posix(),
                "review_template_present": review_template_present,
                "required_human_fields": required_human_fields,
                "required_human_field_count": len(required_human_fields),
                "required_evidence": required_evidence,
                "required_evidence_count": len(required_evidence),
                "record_template_output_command": record_template_output_command,
                "validation_command": validation_command,
                "validation_output_command": validation_output_command,
                "scenario_delivery_unit_plan_ready": (
                    scenario_delivery_unit_plan_summary.get(
                        "scenario_delivery_unit_plan_ready"
                    )
                ),
                "scenario_delivery_unit_plan_lifecycle_step_count": (
                    scenario_delivery_unit_plan_summary.get(
                        "scenario_delivery_unit_plan_lifecycle_step_count"
                    )
                ),
                "scenario_delivery_unit_plan_senior_review_perspective_count": (
                    scenario_delivery_unit_plan_summary.get(
                        "scenario_delivery_unit_plan_senior_review_perspective_count"
                    )
                ),
                "product_claim_allowed": product_claim_allowed,
                "pass_claim_allowed": pass_claim_allowed,
                "approval_collected": approval_collected,
                "trace_ready": trace_ready,
                "claim_boundary": HUMAN_REQUIRED_WORK_MAPPING_CLAIM_BOUNDARY,
            }
        )
    return rows


def _remaining_human_external_gate_audit(
    human_required_work_mapping: list[dict[str, object]],
) -> list[dict[str, object]]:
    mapping_by_id = {
        str(row["scenario_id"]): row
        for row in human_required_work_mapping
    }
    handoff_payload: dict[str, object] = {}
    handoff: dict[str, object] = {}
    if HUMAN_GATE_VALIDATION_HANDOFF_PATH.exists():
        handoff_payload = json.loads(HUMAN_GATE_VALIDATION_HANDOFF_PATH.read_text())
        candidate_handoff = handoff_payload.get("connector_human_gate_validation_handoff")
        if isinstance(candidate_handoff, dict):
            handoff = candidate_handoff
    handoff_rows = handoff.get("scenario_validation_handoff_rows")
    handoff_rows_by_id = (
        {
            str(row.get("scenario_id")): row
            for row in handoff_rows
            if isinstance(row, dict) and row.get("scenario_id")
        }
        if isinstance(handoff_rows, list)
        else {}
    )
    next_scenario_id = handoff.get("next_scenario_id")
    rows = []
    for scenario_id in EXPECTED_HUMAN_GATE_EXECUTION_ORDER:
        mapping = mapping_by_id.get(scenario_id, {})
        handoff_row = handoff_rows_by_id.get(scenario_id, {})
        reviewer_commands = handoff_row.get("reviewer_commands")
        if not isinstance(reviewer_commands, dict):
            reviewer_commands = {}
        remaining_summary = handoff_row.get("remaining_human_evidence_summary")
        if not isinstance(remaining_summary, dict):
            remaining_summary = {}
        blocked_dependencies = handoff_row.get(
            "blocked_by_missing_dependency_unlock_validations"
        )
        if not isinstance(blocked_dependencies, list):
            blocked_dependencies = []
        local_baseline_summary = handoff_row.get("local_baseline_review_input_summary")
        local_baseline_report_count = (
            local_baseline_summary.get("report_count")
            if isinstance(local_baseline_summary, dict)
            else 0
        )
        product_claim_allowed = bool(
            handoff_row.get("product_claim_allowed")
            or mapping.get("product_claim_allowed")
        )
        pass_claim_allowed = bool(
            handoff_row.get("pass_claim_allowed")
            or mapping.get("pass_claim_allowed")
        )
        approval_collected = bool(
            handoff_row.get("approval_collected")
            or mapping.get("approval_collected")
        )
        record_validation_count = handoff_row.get("record_validation_count")
        if not isinstance(record_validation_count, int):
            record_validation_count = 0
        remaining_human_field_count = (
            handoff_row.get("required_human_field_count")
            if isinstance(handoff_row.get("required_human_field_count"), int)
            else mapping.get("required_human_field_count", 0)
        )
        remaining_human_evidence_count = (
            handoff_row.get("required_evidence_count")
            if isinstance(handoff_row.get("required_evidence_count"), int)
            else mapping.get("required_evidence_count", 0)
        )
        why_ai_cannot_verify = mapping.get("why_ai_cannot_verify")
        required_human_action = mapping.get("required_human_action")
        expected_evidence_summary = mapping.get("expected_evidence_summary")
        source_release_impact = mapping.get("source_release_impact")
        source_requirement_count = (
            handoff_row.get("source_requirement_count")
            if isinstance(handoff_row.get("source_requirement_count"), int)
            else mapping.get("source_requirement_count", 0)
        )
        trace_ready = (
            bool(mapping.get("trace_ready"))
            and bool(handoff)
            and handoff_payload.get("final_verdict") == "HUMAN_REQUIRED"
            and handoff_row.get("status") == "HUMAN_REQUIRED"
            and handoff_row.get("owner") == "Human"
            and remaining_summary.get("claim_boundary")
            == EXPECTED_HUMAN_GATE_REMAINING_EVIDENCE_CLAIM_BOUNDARY
            and handoff_row.get("source_requirement_status")
            == "human_external_pending"
            and handoff_row.get("source_requirement_claim_boundary")
            == EXPECTED_HUMAN_GATE_SOURCE_REQUIREMENT_CLAIM_BOUNDARY
            and bool(why_ai_cannot_verify)
            and bool(required_human_action)
            and bool(expected_evidence_summary)
            and bool(source_release_impact)
            and set(reviewer_commands) == {
                "package",
                "record_template_output",
                "validate_record",
                "validate_record_output",
            }
            and not product_claim_allowed
            and not pass_claim_allowed
            and not approval_collected
        )
        rows.append(
            {
                "scenario_id": scenario_id,
                "review_order": handoff_row.get("review_order")
                or mapping.get("review_order"),
                "gate_category": handoff_row.get("gate_category")
                or mapping.get("gate_category"),
                "status": handoff_row.get("status") or "HUMAN_REQUIRED",
                "completion_status": "HUMAN_EXTERNAL_EVIDENCE_PENDING",
                "is_next_human_gate": scenario_id == next_scenario_id,
                "dependency_status": handoff_row.get("dependency_status"),
                "dependency_ready": handoff_row.get("dependency_ready"),
                "blocked_dependency_count": len(blocked_dependencies),
                "blocked_dependency_scenario_ids": blocked_dependencies,
                "record_validation_status": handoff_row.get("record_validation_status"),
                "record_validation_count": record_validation_count,
                "latest_record_validation_ref_present": bool(
                    handoff_row.get("latest_record_validation_ref")
                ),
                "dependency_unlock_allowed": bool(
                    handoff_row.get("latest_record_validation_dependency_unlock_allowed")
                ),
                "structurally_valid_record_validation_present": bool(
                    handoff_row.get("structurally_valid_record_validation_present")
                ),
                "remaining_human_field_count": remaining_human_field_count,
                "remaining_human_evidence_count": remaining_human_evidence_count,
                "why_ai_cannot_verify": why_ai_cannot_verify,
                "required_human_action": required_human_action,
                "expected_evidence_summary": expected_evidence_summary,
                "source_release_impact": source_release_impact,
                "remaining_human_evidence_claim_boundary": remaining_summary.get(
                    "claim_boundary"
                ),
                "source_requirement_count": source_requirement_count,
                "source_requirement_status": handoff_row.get(
                    "source_requirement_status"
                ),
                "reviewer_command_count": len(reviewer_commands),
                "reviewer_commands_present": set(reviewer_commands) == {
                    "package",
                    "record_template_output",
                    "validate_record",
                    "validate_record_output",
                },
                "local_baseline_review_input_count": local_baseline_report_count,
                "product_claim_allowed": product_claim_allowed,
                "pass_claim_allowed": pass_claim_allowed,
                "approval_collected": approval_collected,
                "completion_allowed": False,
                "trace_ready": trace_ready,
                "claim_boundary": REMAINING_HUMAN_EXTERNAL_GATE_AUDIT_CLAIM_BOUNDARY,
            }
        )
    return rows


