def _focused_report_command_exit_code_trace(
    delivery_units: list[dict[str, object]],
) -> list[dict[str, object]]:
    trace: list[dict[str, object]] = []
    expected_counts = EXPECTED_FOCUSED_REPORT_COMMAND_EVIDENCE_EXIT_CODE_COUNTS
    for item in delivery_units:
        exit_code_counts = item["focused_report_command_evidence_exit_code_counts"]
        missing_exit_codes = [
            exit_code for exit_code in expected_counts if exit_code not in exit_code_counts
        ]
        unexpected_exit_codes = [
            exit_code for exit_code in exit_code_counts if exit_code not in expected_counts
        ]
        command_evidence_count = item["focused_report_command_evidence_count"]
        exit_code_count_total = sum(exit_code_counts.values())
        command_count_matches_exit_code_total = (
            command_evidence_count == exit_code_count_total
        )
        expected_exit_code_counts_match = exit_code_counts == expected_counts
        trace_ready = (
            item["focused_report_evidence_trail_ready"]
            and expected_exit_code_counts_match
            and command_count_matches_exit_code_total
            and item["focused_report_command_evidence_schema_invalid_count"] == 0
            and item["focused_report_command_evidence_schema_valid_count"]
            == command_evidence_count
            and command_evidence_count > 0
        )
        trace.append(
            {
                "scenario_id": item["scenario_id"],
                "type": item["type"],
                "phase": item["phase"],
                "focused_report": item["focused_report"],
                "focused_verify_command": item["focused_verify_command"],
                "focused_report_command_evidence_count": command_evidence_count,
                "focused_report_command_evidence_schema_valid_count": item[
                    "focused_report_command_evidence_schema_valid_count"
                ],
                "focused_report_command_evidence_schema_invalid_count": item[
                    "focused_report_command_evidence_schema_invalid_count"
                ],
                "focused_report_command_evidence_exit_code_counts": exit_code_counts,
                "expected_exit_code_counts": expected_counts,
                "exit_code_entry_count": len(exit_code_counts),
                "exit_code_count_total": exit_code_count_total,
                "command_count_matches_exit_code_total": (
                    command_count_matches_exit_code_total
                ),
                "expected_exit_code_counts_match": expected_exit_code_counts_match,
                "missing_exit_codes": missing_exit_codes,
                "unexpected_exit_codes": unexpected_exit_codes,
                "trace_ready": trace_ready,
                "product_claim_allowed": False,
                "live_provider_claim_allowed": False,
                "human_acceptance_claim_allowed": False,
                "production_claim_allowed": False,
                "full_goal_completion_allowed": False,
                "claim_boundary": "stable_exit_code_transcripts_local_fixture_only",
                "trace_claim_boundary": (
                    FOCUSED_REPORT_COMMAND_EXIT_CODE_TRACE_CLAIM_BOUNDARY
                ),
            }
        )
    return trace


