def _scenario_delivery_loop_trace(
    delivery_units: list[dict[str, object]],
) -> list[dict[str, object]]:
    trace: list[dict[str, object]] = []
    for item in delivery_units:
        verification_result_ready = (
            item["verification_result_documented"]
            and item["focused_report_evidence_trail_ready"]
            and item["focused_gate_status"] == "success"
            and item["focused_gate_blocking_count"] == 0
            and item["focused_gate_error_count"] == 0
        )
        step_statuses = {
            "research_perspectives": item["research_perspective_text_trace_ready"],
            "implementation_approach": item["implementation_approach_text_trace_ready"],
            "smallest_complete_solution": item["smallest_solution_text_trace_ready"],
            "refactor_and_hardening": item["refactor_hardening_text_trace_ready"],
            "verification_result": verification_result_ready,
            "documented_result": item["documented_result_text_trace_ready"],
            "adoption_contribution": item["adoption_contribution_text_trace_ready"],
        }
        ready_steps = [
            step for step, ready in step_statuses.items() if ready
        ]
        missing_steps = [
            step for step, ready in step_statuses.items() if not ready
        ]
        move_to_next_allowed = (
            not item["current_unit_must_close_before_next"]
            or item["move_to_next_allowed_by_manifest"]
        )
        trace_ready = (
            item["status"] == "delivery_unit_closed"
            and item["lifecycle_marker_order_trace_ready"]
            and item["completion_method_trace_ready"]
            and all(step_statuses.values())
            and move_to_next_allowed
        )
        trace.append(
            {
                "delivery_sequence_index": item["delivery_sequence_index"],
                "delivery_sequence_total": item["delivery_sequence_total"],
                "scenario_id": item["scenario_id"],
                "type": item["type"],
                "phase": item["phase"],
                "result_doc": item["result_doc"],
                "focused_report": item["focused_report"],
                "focused_gate_status": item["focused_gate_status"],
                "previous_scenario_id": item["previous_scenario_id"],
                "next_scenario_id": item["next_scenario_id"],
                "current_unit_must_close_before_next": item[
                    "current_unit_must_close_before_next"
                ],
                "move_to_next_allowed_by_manifest": item[
                    "move_to_next_allowed_by_manifest"
                ],
                "move_to_next_allowed_by_loop": move_to_next_allowed,
                "loop_step_statuses": step_statuses,
                "loop_step_count": len(step_statuses),
                "loop_step_ready_count": len(ready_steps),
                "loop_step_missing_count": len(missing_steps),
                "loop_steps_ready": ready_steps,
                "loop_steps_missing": missing_steps,
                "research_perspectives_ready": step_statuses[
                    "research_perspectives"
                ],
                "implementation_approach_ready": step_statuses[
                    "implementation_approach"
                ],
                "smallest_complete_solution_ready": step_statuses[
                    "smallest_complete_solution"
                ],
                "refactor_and_hardening_ready": step_statuses[
                    "refactor_and_hardening"
                ],
                "verification_result_ready": step_statuses["verification_result"],
                "documented_result_ready": step_statuses["documented_result"],
                "adoption_contribution_ready": step_statuses[
                    "adoption_contribution"
                ],
                "lifecycle_order_ready": item["lifecycle_marker_order_trace_ready"],
                "completion_method_ready": item["completion_method_trace_ready"],
                "trace_ready": trace_ready,
                "product_claim_allowed": False,
                "live_provider_claim_allowed": False,
                "human_acceptance_claim_allowed": False,
                "production_claim_allowed": False,
                "full_goal_completion_allowed": False,
                "claim_boundary": SCENARIO_DELIVERY_LOOP_TRACE_CLAIM_BOUNDARY,
            }
        )
    return trace


