def _source_requirement_coverage_row(item: dict[str, object]) -> str:
    scenario_ids = item["scenario_ids"]
    ai_scenario_ids = item["ai_scenario_ids"]
    human_required_scenario_ids = item["human_required_scenario_ids"]
    return (
        f"| `{item['requirement_id']}` | "
        f"{', '.join(f'`{scenario_id}`' for scenario_id in scenario_ids)} | "
        f"`{item['ai_scenario_count']}` | "
        f"`{item['human_required_scenario_count']}` | "
        f"{', '.join(f'`{scenario_id}`' for scenario_id in ai_scenario_ids) or '`none`'} | "
        f"{', '.join(f'`{scenario_id}`' for scenario_id in human_required_scenario_ids) or '`none`'} | "
        f"`{item['trace_ready']}` | "
        f"`{item['operator_handoff_ready']}` | "
        f"`{item['source_requirement_acceptance_claim_allowed']}` | "
        f"`{item['release_claim_allowed']}` | "
        f"`{item['human_acceptance_claim_allowed']}` | "
        f"`{item['completion_claim_allowed']}` | "
        f"`{item['completion_blocked_until_source_requirement_evidence']}` | "
        f"`{item['claim_boundary']}` |"
    )


def _source_requirement_proof_split_row(item: dict[str, object]) -> str:
    ai_delivery_unit_ids = item["ai_delivery_unit_ids"]
    human_required_scenario_ids = item["human_required_scenario_ids"]
    return (
        f"| `{item['requirement_id']}` | `{item['proof_status']}` | "
        f"{', '.join(f'`{scenario_id}`' for scenario_id in ai_delivery_unit_ids) or '`none`'} | "
        f"{', '.join(f'`{scenario_id}`' for scenario_id in human_required_scenario_ids) or '`none`'} | "
        f"`{item['operator_handoff_ready']}` | "
        f"`{item['source_requirement_acceptance_claim_allowed']}` | "
        f"`{item['human_external_acceptance_claim_allowed']}` | "
        f"`{item['release_claim_allowed']}` | "
        f"`{item['completion_claim_allowed']}` | "
        f"`{item['completion_blocked_until_full_requirement_evidence']}` | "
        f"`{item['claim_boundary']}` |"
    )


def _source_requirement_proof_split_rows(
    matrix_rows: list[dict[str, str]],
) -> list[str]:
    return [
        _source_requirement_proof_split_row(item)
        for item in _source_requirement_proof_split(matrix_rows)
    ]


def _related_human_dependency_index_rows(
    matrix_rows: list[dict[str, str]],
) -> list[str]:
    human_rows = [
        row
        for row in matrix_rows
        if row.get("owner") == "Human" and row.get("status") == "HUMAN_REQUIRED"
    ]
    ai_rows = sorted(
        [
            row
            for row in matrix_rows
            if row.get("owner") == "AI" and row.get("status") == "PASS"
        ],
        key=lambda item: _scenario_number(item["scenario_id"]),
    )
    rows = []
    for row in ai_rows:
        dependencies = _related_human_required_dependencies(row, human_rows)
        related_requirements = sorted(
            {
                requirement
                for dependency in dependencies
                for requirement in dependency["overlapping_requirement_ids"]
            }
        )
        dependency_labels = [
            (
                f"`{dependency['scenario_id']}` "
                f"({', '.join(f'`{requirement}`' for requirement in dependency['overlapping_requirement_ids'])})"
            )
            for dependency in dependencies
        ]
        rows.append(
            (
                f"| `{row['scenario_id']}` | "
                f"{', '.join(f'`{requirement}`' for requirement in related_requirements) or '`none`'} | "
                f"{', '.join(dependency_labels) or '`none`'} | "
                f"`{len(dependencies)}` | "
                f"`True` | "
                f"`False` | "
                f"`False` | "
                f"`False` | "
                f"`{bool(dependencies)}` | "
                f"`ai_local_delivery_unit_pass_does_not_close_related_human_required_gates` |"
            )
        )
    return rows


def _delivery_sequence_trace_rows(matrix_rows: list[dict[str, str]]) -> list[str]:
    manifest = _build_scenario_delivery_unit_manifest(matrix_rows)
    rows = []
    for item in manifest["delivery_sequence_trace"]:
        rows.append(
            (
                f"| `{item['delivery_sequence_index']}/{item['delivery_sequence_total']}` | "
                f"`{item['scenario_id']}` | "
                f"`{item['previous_scenario_id'] or 'none'}` | "
                f"`{item['next_scenario_id'] or 'none'}` | "
                f"`{item['previous_delivery_unit_required_closed']}` | "
                f"`{item['current_unit_must_close_before_next']}` | "
                f"`{item['move_to_next_allowed_by_manifest']}` |"
            )
        )
    return rows


def _focused_report_readiness_counts_text(counts: dict[str, int]) -> str:
    dimensions = [
        "HUMAN_REQUIRED",
        "LOCAL_FIXTURE_VERIFIED",
        "NOT_VERIFIED",
        "OUT_OF_SCOPE_READ_ONLY",
    ]
    return ", ".join(
        f"`{dimension}={counts.get(dimension, 0)}`"
        for dimension in dimensions
    )


