def _focused_report_readiness_dimension_trace_rows(
    matrix_rows: list[dict[str, str]],
) -> list[str]:
    manifest = _build_scenario_delivery_unit_manifest(matrix_rows)

    def code_list(values: list[str]) -> str:
        return ", ".join(f"`{value}`" for value in values) or "`none`"

    return [
        (
            f"| `{item['scenario_id']}` | "
            f"`{item['readiness_dimension_total']}` | "
            f"`{item['local_fixture_verified_count']}` | "
            f"`{item['human_required_count']}` | "
            f"`{item['not_verified_count']}` | "
            f"`{item['out_of_scope_read_only_count']}` | "
            f"{code_list(item['local_fixture_verified_dimensions'])} | "
            f"{code_list(item['human_required_dimensions'])} | "
            f"{code_list(item['not_verified_dimensions'])} | "
            f"{code_list(item['out_of_scope_read_only_dimensions'])} | "
            f"`{item['product_claim_allowed']}` | "
            f"`{item['live_provider_claim_allowed']}` | "
            f"`{item['human_acceptance_claim_allowed']}` | "
            f"`{item['production_claim_allowed']}` | "
            f"`{item['full_goal_completion_allowed']}` | "
            f"`{item['trace_ready']}` | "
            f"`{item['claim_boundary']}` |"
        )
        for item in manifest["focused_report_readiness_dimension_trace"]
    ]


