def _source_requirement_proof_split(matrix_rows: list[dict[str, str]]) -> list[dict[str, object]]:
    coverage = {
        requirement: {"ai": [], "human": []}
        for requirement in SOURCE_REQUIREMENTS
    }
    for row in matrix_rows:
        scenario_id = row.get("scenario_id", "")
        owner = row.get("owner", "")
        for requirement in _requirement_ids(row.get("related_requirements", "")):
            if requirement not in coverage:
                continue
            if owner == "AI":
                coverage[requirement]["ai"].append(scenario_id)
            elif owner == "Human":
                coverage[requirement]["human"].append(scenario_id)

    proof_split: list[dict[str, object]] = []
    for requirement in SOURCE_REQUIREMENTS:
        ai_scenario_ids = coverage[requirement]["ai"]
        human_scenario_ids = coverage[requirement]["human"]
        has_ai_coverage = bool(ai_scenario_ids)
        has_human_dependency = bool(human_scenario_ids)
        if has_ai_coverage and has_human_dependency:
            proof_status = "ai_local_closed_human_external_pending"
            claim_boundary = "ai_local_coverage_does_not_close_human_external_requirement_slice"
        elif has_human_dependency:
            proof_status = "human_external_pending"
            claim_boundary = "human_external_requirement_slice_pending"
        elif has_ai_coverage:
            proof_status = "ai_local_closed"
            claim_boundary = "ai_local_delivery_units_close_current_ai_verifiable_slice_only"
        else:
            proof_status = "missing"
            claim_boundary = "no_matrix_scenario_maps_to_requirement"
        proof_split.append(
            {
                "requirement_id": requirement,
                "ai_delivery_unit_ids": ai_scenario_ids,
                "ai_delivery_unit_count": len(ai_scenario_ids),
                "human_required_scenario_ids": human_scenario_ids,
                "human_required_scenario_count": len(human_scenario_ids),
                "has_ai_delivery_unit_coverage": has_ai_coverage,
                "has_human_required_dependency": has_human_dependency,
                "proof_status": proof_status,
                "operator_handoff_ready": has_ai_coverage or has_human_dependency,
                "source_requirement_acceptance_claim_allowed": False,
                "human_external_acceptance_claim_allowed": False,
                "release_claim_allowed": False,
                "completion_claim_allowed": False,
                "completion_blocked_until_full_requirement_evidence": True,
                "claim_boundary": claim_boundary,
            }
        )
    return proof_split


def _related_human_required_dependencies(
    row: dict[str, str],
    human_rows: list[dict[str, str]],
) -> list[dict[str, object]]:
    source_requirement_ids = set(_requirement_ids(row.get("related_requirements", "")))
    dependencies = []
    for human_row in human_rows:
        overlapping_requirement_ids = sorted(
            source_requirement_ids
            & set(_requirement_ids(human_row.get("related_requirements", "")))
        )
        if not overlapping_requirement_ids:
            continue
        dependencies.append(
            {
                "scenario_id": human_row["scenario_id"],
                "phase": human_row["phase"],
                "overlapping_requirement_ids": overlapping_requirement_ids,
                "proof_surface": human_row["proof_surface"],
                "claim_boundary": human_row["claim_boundary"],
                "evidence_required": human_row["evidence_required"],
            }
        )
    return dependencies


