def _source_required_implementation_rows(matrix_rows: list[dict[str, str]]) -> list[str]:
    rows = []
    for row in sorted(
        matrix_rows,
        key=lambda item: (
            1 if item["scenario_id"].startswith("CS-CH-H") else 0,
            _scenario_number(item["scenario_id"]),
            item["scenario_id"],
        ),
    ):
        required_implementation = SCENARIO_REQUIRED_IMPLEMENTATIONS.get(
            row["scenario_id"],
            "",
        )
        trace_ready = bool(required_implementation)
        human_blocked = row.get("owner") == "Human"
        rows.append(
            (
                f"| `{row['scenario_id']}` | `{row.get('phase', '')}` | "
                f"`{row.get('owner', '')}` | "
                f"`{SCENARIO_REQUIRED_IMPLEMENTATION_SOURCE_REF}` | "
                f"`{trace_ready}` | `{trace_ready}` | "
                f"`{human_blocked}` | `False` | `False` | `False` | `False` | "
                f"`source_work_mapping_is_traceability_not_release_readiness` | "
                f"{required_implementation} |"
            )
        )
    return rows


