def _source_completion_criteria_audit_rows(
    matrix_rows: list[dict[str, str]],
) -> list[str]:
    if SCENARIO_DELIVERY_UNIT_MANIFEST.exists():
        delivery_units = json.loads(SCENARIO_DELIVERY_UNIT_MANIFEST.read_text()).get(
            "delivery_units",
            [],
        )
    else:
        delivery_units = _build_scenario_delivery_unit_manifest(matrix_rows)[
            "delivery_units"
        ]
    source_human_required_checks = _source_human_required_checks(matrix_rows)
    human_required_work_mapping = _human_required_work_mapping(
        [row for row in matrix_rows if row["owner"] == "Human"]
    )
    source_completion_criteria_audit = _source_completion_criteria_audit(
        matrix_rows,
        delivery_units,
        source_human_required_checks,
        human_required_work_mapping,
    )
    return [
        (
            f"| `{item['criterion_id']}` | {item['source_text']} | "
            f"`{item['source_ref']}` | `{item['current_status']}` | "
            f"{item['current_evidence']} | `{item['full_goal_completion_allowed']}` |"
        )
        for item in source_completion_criteria_audit
    ]


