def _sha256(path: Path) -> str:
    digest = hashlib.sha256()
    with path.open("rb") as file:
        for chunk in iter(lambda: file.read(1024 * 1024), b""):
            digest.update(chunk)
    return digest.hexdigest()


def _line_count(path: Path) -> int:
    with path.open(encoding="utf-8") as file:
        return sum(1 for _ in file)


def _canonical_json_sha256(payload: object) -> str:
    encoded = json.dumps(payload, sort_keys=True, separators=(",", ":")).encode("utf-8")
    return hashlib.sha256(encoded).hexdigest()


def _load_connector_contract_report(
    report_path: Path,
    errors: list[str] | None = None,
    label: str = "connector report",
) -> dict[str, object]:
    report = json.loads(report_path.read_text())
    if not isinstance(report, dict):
        if errors is not None:
            errors.append(f"{label} must be a JSON object: {report_path.relative_to(ROOT)}")
        return {}
    if report.get("compact_evidence_layout") != "content_addressed_shared_v1":
        return report

    shared_ref = report.get("shared_evidence_ref")
    if not isinstance(shared_ref, dict):
        if errors is not None:
            errors.append(f"{label} compact report missing shared_evidence_ref")
        return report
    shared_path_value = shared_ref.get("path")
    if not isinstance(shared_path_value, str) or not shared_path_value:
        if errors is not None:
            errors.append(f"{label} compact report shared_evidence_ref.path missing")
        return report
    shared_path = (ROOT / shared_path_value).resolve()
    if not shared_path.exists():
        if errors is not None:
            errors.append(f"{label} compact shared evidence missing: {shared_path_value}")
        return report
    actual_shared_sha = _sha256(shared_path)
    expected_shared_sha = shared_ref.get("sha256")
    if expected_shared_sha != actual_shared_sha and errors is not None:
        errors.append(
            f"{label} compact shared evidence sha256 expected {expected_shared_sha}, "
            f"found {actual_shared_sha}"
        )
    shared_payload = json.loads(shared_path.read_text())
    if not isinstance(shared_payload, dict):
        if errors is not None:
            errors.append(f"{label} compact shared evidence must be a JSON object")
        return report
    sections = shared_payload.get("sections")
    if not isinstance(sections, dict):
        if errors is not None:
            errors.append(f"{label} compact shared evidence missing sections")
        return report
    section_refs = shared_ref.get("sections") if isinstance(shared_ref.get("sections"), dict) else {}
    expanded = dict(report)
    for section_name, section_payload in sections.items():
        expanded[section_name] = section_payload
        expected_section_ref = section_refs.get(section_name) if isinstance(section_refs, dict) else None
        if isinstance(expected_section_ref, dict):
            expected_section_sha = expected_section_ref.get("sha256")
            actual_section_sha = _canonical_json_sha256(section_payload)
            if expected_section_sha != actual_section_sha and errors is not None:
                errors.append(
                    f"{label} compact section {section_name} sha256 expected "
                    f"{expected_section_sha}, found {actual_section_sha}"
                )
    return expanded


def _validate_source_inputs(errors: list[str], index_text: str) -> None:
    for token in SOURCE_RECONCILIATION_TOKENS:
        if token not in index_text:
            errors.append(f"engineering trail index missing source reconciliation token: {token}")
    for source in SOURCE_INPUTS:
        path = source["path"]
        label = source["label"]
        if not path.exists():
            errors.append(f"source input missing for {label}: {path}")
            continue
        actual_sha256 = _sha256(path)
        if actual_sha256 != source["sha256"]:
            errors.append(
                f"source input hash mismatch for {label}: expected {source['sha256']}, found {actual_sha256}"
            )
        actual_line_count = _line_count(path)
        if actual_line_count != source["line_count"]:
            errors.append(
                f"source input line count mismatch for {label}: "
                f"expected {source['line_count']}, found {actual_line_count}"
            )
        for token in source["index_tokens"]:
            if token not in index_text:
                errors.append(f"engineering trail index missing source input token for {label}: {token}")


def _compact_report_paths() -> list[Path]:
    return [
        AGGREGATE_REPORT_PATH,
        *[
            CONNECTOR_CONTRACT_ADAPTER_REPORT_DIR / "scenarios" / f"{scenario_id}.json"
            for scenario_id in sorted(EXPECTED_AI_SCENARIO_IDS, key=_scenario_number)
        ],
    ]


def _json_string_paths(value: object, path: tuple[str, ...] = ()) -> list[tuple[tuple[str, ...], str]]:
    if isinstance(value, str):
        return [(path, value)]
    if isinstance(value, list):
        rows: list[tuple[tuple[str, ...], str]] = []
        for item in value:
            rows.extend(_json_string_paths(item, (*path, "[]")))
        return rows
    if isinstance(value, dict):
        rows = []
        for key, item in value.items():
            rows.extend(_json_string_paths(item, (*path, str(key))))
        return rows
    return []


def _validate_path_portability(errors: list[str]) -> None:
    repo_docs = [
        README_PATH,
        CONTRACT_PATH,
        ENGINEERING_TRAIL_INDEX,
        CONNECTORHUB_REVIEWER_GUIDE,
        CONNECTORHUB_FEEDBACK_RESOLUTION_REPORT,
        VS2_CURRENT_VERIFICATION_REPORT,
        CONNECTORHUB_H04_ADR,
        CONNECTORHUB_SPLIT_ADR,
        *[source["path"] for source in SOURCE_INPUTS],
    ]
    for path in repo_docs:
        if not path.exists():
            continue
        if "/Users/" in path.read_text(encoding="utf-8", errors="replace"):
            errors.append(
                f"portable evidence path guard found unguarded /Users/ reference in {path.relative_to(ROOT)}"
            )

    expected_claim_boundary = "absolute_paths_are_historical_transcript_metadata_not_portable_evidence"
    report_allowed_absolute_paths = {
        ("output_path",),
        ("source_report", "output_path"),
    }
    for report_path in _compact_report_paths():
        if not report_path.exists():
            continue
        payload = json.loads(report_path.read_text())
        portability = payload.get("path_portability")
        if not isinstance(portability, dict):
            errors.append(f"compact report missing path_portability: {report_path.relative_to(ROOT)}")
            continue
        if portability.get("claim_boundary") != expected_claim_boundary:
            errors.append(f"compact report path_portability claim_boundary mismatch: {report_path.relative_to(ROOT)}")
        if portability.get("portable_report_path") != report_path.relative_to(ROOT).as_posix():
            errors.append(f"compact report portable_report_path mismatch: {report_path.relative_to(ROOT)}")
        if "tmp/scenario/" in report_path.read_text(encoding="utf-8", errors="replace"):
            prefixes = portability.get("regenerable_transcript_path_prefixes")
            if not isinstance(prefixes, list) or "tmp/scenario/" not in prefixes:
                errors.append(f"compact report tmp/scenario refs are not marked regenerable: {report_path.relative_to(ROOT)}")
        for json_path, string_value in _json_string_paths(payload):
            if "/Users/" in string_value and json_path not in report_allowed_absolute_paths:
                errors.append(
                    "compact report has unguarded absolute path at "
                    f"{report_path.relative_to(ROOT)}:{'.'.join(json_path)}"
                )

    if COMPACT_SHARED_EVIDENCE_PATH.exists():
        shared_payload = json.loads(COMPACT_SHARED_EVIDENCE_PATH.read_text())
        portability = shared_payload.get("path_portability")
        if not isinstance(portability, dict):
            errors.append("compact shared evidence missing path_portability")
        elif portability.get("claim_boundary") != expected_claim_boundary:
            errors.append("compact shared evidence path_portability claim_boundary mismatch")
        allowed_shared_absolute_paths = set()
        if isinstance(portability, dict):
            declared_fields = portability.get("historical_absolute_path_fields")
            if isinstance(declared_fields, list):
                allowed_shared_absolute_paths = {
                    tuple(str(field).split("."))
                    for field in declared_fields
                    if isinstance(field, str)
                }
        if "tmp/scenario/" in COMPACT_SHARED_EVIDENCE_PATH.read_text(encoding="utf-8", errors="replace"):
            prefixes = portability.get("regenerable_transcript_path_prefixes") if isinstance(portability, dict) else None
            if not isinstance(prefixes, list) or "tmp/scenario/" not in prefixes:
                errors.append("compact shared evidence tmp/scenario refs are not marked regenerable")
        for json_path, string_value in _json_string_paths(shared_payload):
            if "/Users/" in string_value and json_path not in allowed_shared_absolute_paths:
                errors.append(
                    "compact shared evidence has unguarded absolute path at "
                    f"{'.'.join(json_path)}"
                )

    if COMPACT_REPORT_MANIFEST_PATH.exists():
        manifest_payload = json.loads(COMPACT_REPORT_MANIFEST_PATH.read_text())
        portability = manifest_payload.get("path_portability")
        if not isinstance(portability, dict):
            errors.append("compact manifest missing path_portability")
        elif portability.get("claim_boundary") != expected_claim_boundary:
            errors.append("compact manifest path_portability claim_boundary mismatch")
        allowed_manifest_absolute_paths = {
            ("aggregate_report", "source_report", "output_path"),
            ("scenario_reports", "[]", "source_report", "output_path"),
        }
        for json_path, string_value in _json_string_paths(manifest_payload):
            if "/Users/" in string_value and json_path not in allowed_manifest_absolute_paths:
                errors.append(
                    "compact manifest has unguarded absolute path at "
                    f"{'.'.join(json_path)}"
                )

    if SCENARIO_DELIVERY_UNIT_MANIFEST.exists():
        delivery_payload = json.loads(SCENARIO_DELIVERY_UNIT_MANIFEST.read_text())
        portability = delivery_payload.get("path_portability")
        expected_delivery_boundary = (
            "tmp_scenario_refs_are_regenerable_local_transcripts_not_durable_evidence"
        )
        if not isinstance(portability, dict):
            errors.append("scenario delivery-unit manifest missing path_portability")
        else:
            if portability.get("claim_boundary") != expected_delivery_boundary:
                errors.append("scenario delivery-unit manifest path_portability claim_boundary mismatch")
            expected_path = SCENARIO_DELIVERY_UNIT_MANIFEST.relative_to(ROOT).as_posix()
            if portability.get("portable_report_path") != expected_path:
                errors.append("scenario delivery-unit manifest portable_report_path mismatch")
            prefixes = portability.get("regenerable_transcript_path_prefixes")
            if "tmp/scenario/" in SCENARIO_DELIVERY_UNIT_MANIFEST.read_text(
                encoding="utf-8",
                errors="replace",
            ) and (not isinstance(prefixes, list) or "tmp/scenario/" not in prefixes):
                errors.append("scenario delivery-unit manifest tmp/scenario refs are not marked regenerable")


