                    if not isinstance(validation, dict):
                        errors.append("generated H04 record draft validation missing nested report")
                    else:
                        if validation.get("status") != "record_structurally_invalid":
                            errors.append("generated H04 record draft must remain structurally invalid")
                        if validation.get("dependency_unlock_allowed_by_validator") is not False:
                            errors.append("generated H04 record draft must not unlock dependencies")
