def _read_pinned_human_gate_report_payload(
    errors: list[str],
    path: Path,
    label: str,
) -> dict[str, object] | None:
    if not path.exists():
        errors.append(f"missing pinned human-gate {label}: {path.relative_to(ROOT)}")
        return None
    try:
        payload = json.loads(path.read_text())
    except (OSError, ValueError) as error:
        errors.append(
            f"pinned human-gate {label} is not valid JSON: "
            f"{path.relative_to(ROOT)} ({error})"
        )
        return None
    if not isinstance(payload, dict):
        errors.append(f"pinned human-gate {label} must be a JSON object: {path.relative_to(ROOT)}")
        return None
    return payload


def _expected_required_evidence_from_pinned_package(
    errors: list[str],
    scenario_id: str,
) -> list[object] | None:
    path = HUMAN_GATE_PACKAGE_REPORT_PATHS[scenario_id]
    payload = _read_pinned_human_gate_report_payload(
        errors,
        path,
        f"package report for {scenario_id}",
    )
    if payload is None:
        return None
    package = payload.get("connector_human_gate_package")
    required_record = (
        package.get("required_human_record")
        if isinstance(package, dict)
        else None
    )
    required_evidence = (
        required_record.get("required_evidence")
        if isinstance(required_record, dict)
        else None
    )
    if not isinstance(required_evidence, list) or not required_evidence:
        errors.append(f"{scenario_id} pinned package missing required_human_record.required_evidence")
        return None
    return required_evidence


