def _validate_human_gate_readiness_report_payload(
    errors: list[str],
    report_payload: dict[str, object],
    expected_human_ids: list[str],
    expected_validation_count: int,
) -> None:
    if report_payload.get("schema_version") != "cs.cli.v0":
        errors.append("human-gate readiness report schema_version mismatch")
    if report_payload.get("command") != "cornerstone connector human-gate report":
        errors.append("human-gate readiness report command mismatch")
    if report_payload.get("status") != "success":
        errors.append("human-gate readiness report status expected success")
    if report_payload.get("errors") != []:
        errors.append("human-gate readiness report expected no errors")
    report = report_payload.get("connector_human_gate_readiness_report")
    if not isinstance(report, dict):
        errors.append("human-gate readiness report missing connector_human_gate_readiness_report object")
        return
    _validate_human_gate_completion_boundary(
        errors,
        report,
        "human-gate readiness report",
    )
    if report_payload.get("final_verdict") != "HUMAN_REQUIRED":
        errors.append("human-gate readiness report envelope final_verdict must remain HUMAN_REQUIRED")
    envelope_summary = report_payload.get("summary")
    if not isinstance(envelope_summary, dict):
        errors.append("human-gate readiness report envelope missing summary")
    else:
        _validate_human_gate_completion_boundary(
            errors,
            envelope_summary,
            "human-gate readiness report envelope summary",
        )
        expected_summary_fields = {
            "report_id": report.get("report_id"),
            "readiness_report_id": report.get("report_id"),
            "scenario_count": 7,
            "human_required_count": 7,
            "final_verdict": "HUMAN_REQUIRED",
            "weakest_applicable_scenario_result": "HUMAN_REQUIRED",
            "senior_review_perspectives_ready_count": 7,
            "scenario_delivery_unit_plan_ready_count": 7,
            "scenario_delivery_unit_plan_missing_count": 0,
            "scenario_delivery_unit_plan_product_claims_allowed": 0,
            "scenario_delivery_unit_plan_pass_claims_allowed": 0,
            "scenario_delivery_unit_plan_approvals_collected": 0,
            "scenario_delivery_unit_plan_dependency_unlock_allowed": 0,
            "validation_count": expected_validation_count,
            "structurally_valid_record_validation_count": expected_validation_count,
            "senior_review_perspective_findings_complete_count": expected_validation_count,
            "evidence_packet_manifest_complete_count": expected_validation_count,
            "dependency_unlock_allowed_count": expected_validation_count,
            "dependency_unlock_denied_count": 0,
            "pass_claims_allowed_by_validations": 0,
            "product_claims_allowed_by_validations": 0,
            "record_bodies_persisted_by_validations": 0,
            "product_feature_claims": "CONNECTOR_HUB_HUMAN_GATES_PREPARED_HUMAN_EVIDENCE_REQUIRED",
        }
        for key, expected in expected_summary_fields.items():
            if envelope_summary.get(key) != expected:
                errors.append(
                    f"human-gate readiness report envelope summary {key} expected {expected}, "
                    f"found {envelope_summary.get(key)}"
                )
    expected_report_fields = {
        "final_verdict": "HUMAN_REQUIRED",
        "human_required_count": 7,
        "scenario_count": 7,
        "package_supported_count": 7,
        "evidence_packet_ready_count": 7,
        "senior_review_perspectives_ready_count": 7,
        "no_pass_boundary_ready_count": 7,
        "scenario_first_runbook_ready_count": 7,
        "reject_conditions_ready_count": 7,
        "scenario_delivery_unit_plan_ready_count": 7,
        "scenario_delivery_unit_plan_missing": [],
        "scenario_delivery_unit_plan_product_claims_allowed": [],
        "scenario_delivery_unit_plan_pass_claims_allowed": [],
        "scenario_delivery_unit_plan_approvals_collected": [],
        "scenario_delivery_unit_plan_dependency_unlock_allowed": [],
        "product_feature_claims": "CONNECTOR_HUB_HUMAN_GATES_PREPARED_HUMAN_EVIDENCE_REQUIRED",
        "execution_queue_scenario_order": EXPECTED_HUMAN_GATE_EXECUTION_ORDER,
    }
    for key, expected in expected_report_fields.items():
        if report.get(key) != expected:
            errors.append(f"human-gate readiness report {key} expected {expected}, found {report.get(key)}")
    if report.get("missing_templates") != [] or report.get("row_status_issues") != []:
        errors.append("human-gate readiness report must have no missing templates or row status issues")
    negative_evidence = report.get("negative_evidence")
    if not isinstance(negative_evidence, dict) or not _non_mutation_values_ready(negative_evidence):
        errors.append("human-gate readiness report negative_evidence must be all zero/false")
    non_mutation_report = report.get("non_mutation_evidence")
    if not isinstance(non_mutation_report, dict):
        errors.append("human-gate readiness report missing non_mutation_evidence")
    else:
        expected_non_mutation = {
            "approval_collected_by_ai": False,
            "external_mutations_executed_by_report": 0,
            "human_decisions_recorded_by_report": 0,
            "human_record_validations_executed_by_report": expected_validation_count,
            "live_provider_calls_executed_by_report": 0,
            "provider_mutations_executed_by_report": 0,
            "record_bodies_persisted_by_report": False,
            "secret_material_read_by_report": False,
        }
        for key, expected in expected_non_mutation.items():
            if non_mutation_report.get(key) != expected:
                errors.append(
                    f"human-gate readiness report non_mutation_evidence {key} expected {expected}, "
                    f"found {non_mutation_report.get(key)}"
                )
    scenario_results = report.get("scenario_results")
    if not isinstance(scenario_results, list) or len(scenario_results) != 7:
        errors.append("human-gate readiness report expected seven scenario_results")
        return
    result_ids = sorted(row.get("scenario_id", "") for row in scenario_results if isinstance(row, dict))
    if result_ids != expected_human_ids:
        errors.append(f"human-gate readiness report scenario IDs expected {expected_human_ids}, found {result_ids}")
    for row in scenario_results:
        if not isinstance(row, dict):
            errors.append("human-gate readiness report contains non-object scenario row")
            continue
        scenario_id = row.get("scenario_id", "")
        if row.get("status") != "HUMAN_REQUIRED":
            errors.append(f"{scenario_id} human-gate readiness row status must remain HUMAN_REQUIRED")
        if row.get("owner") != "Human":
            errors.append(f"{scenario_id} human-gate readiness row owner must remain Human")
        if row.get("product_claim_allowed") is not False:
            errors.append(f"{scenario_id} human-gate readiness row must not allow product claim")
        if row.get("pass_claim_allowed_without_human_record") is not False:
            errors.append(f"{scenario_id} human-gate readiness row must not allow PASS without human record")
        _validate_h04_local_baseline_review_inputs(
            errors,
            scenario_id,
            row,
            required_preflight_bundle_alias_field="local_baseline_preflight_bundle",
            required_preflight_bundle_alias_context="CS-CH-H04 readiness row local_baseline_preflight_bundle",
        )
        if row.get("package_supported") is not True or row.get("template_structure_ready") is not True:
            errors.append(f"{scenario_id} human-gate readiness row must keep package/template ready")
        expected_source_requirements = EXPECTED_HUMAN_GATE_SOURCE_REQUIREMENTS[str(scenario_id)]
        if row.get("source_requirement_ids") != expected_source_requirements:
            errors.append(
                f"{scenario_id} human-gate readiness row source_requirement_ids expected "
                f"{expected_source_requirements}, found {row.get('source_requirement_ids')}"
            )
        if row.get("source_requirement_count") != len(expected_source_requirements):
            errors.append(f"{scenario_id} human-gate readiness row source_requirement_count mismatch")
        if row.get("source_requirement_status") != "human_external_pending":
            errors.append(f"{scenario_id} human-gate readiness row source_requirement_status mismatch")
        if row.get("source_requirement_claim_boundary") != EXPECTED_HUMAN_GATE_SOURCE_REQUIREMENT_CLAIM_BOUNDARY:
            errors.append(f"{scenario_id} human-gate readiness row source_requirement_claim_boundary mismatch")
        expected_unlock_present = expected_validation_count == 7
        if row.get("dependency_unlock_record_validation_present") is not expected_unlock_present:
            errors.append(
                f"{scenario_id} human-gate readiness row dependency unlock presence expected "
                f"{expected_unlock_present}, found {row.get('dependency_unlock_record_validation_present')}"
            )
        if row.get("package_command") != f"cornerstone connector human-gate package --scenario {scenario_id} --json":
            errors.append(f"{scenario_id} human-gate readiness row package_command mismatch")
        if row.get("record_template_output_command") != (
            f"cornerstone connector human-gate package --scenario {scenario_id} "
            "--json --record-template-output <reviewer-record-template.json>"
        ):
            errors.append(f"{scenario_id} human-gate readiness row record_template_output_command mismatch")
        if row.get("record_validation_command") != (
            f"cornerstone connector human-gate validate-record --scenario {scenario_id} "
            "--record-file <json> --json"
        ):
            errors.append(f"{scenario_id} human-gate readiness row record_validation_command mismatch")
        if row.get("record_validation_output_command") != (
            f"cornerstone connector human-gate validate-record --scenario {scenario_id} "
            "--record-file <json> --json --output <redacted-validation-envelope.json>"
        ):
            errors.append(f"{scenario_id} human-gate readiness row record_validation_output_command mismatch")
        proposed_record_template = row.get("proposed_record_template")
        if not isinstance(proposed_record_template, dict):
            errors.append(f"{scenario_id} human-gate readiness row missing proposed_record_template")
        else:
            if proposed_record_template.get("schema_version") != "cs.connector_human_gate_record_template.v1":
                errors.append(f"{scenario_id} human-gate readiness row proposed_record_template schema mismatch")
            if proposed_record_template.get("status") != "blank_template_requires_human_evidence":
                errors.append(f"{scenario_id} human-gate readiness row proposed_record_template status mismatch")
            if proposed_record_template.get("pass_claim_allowed_by_template") is not False:
                errors.append(f"{scenario_id} human-gate readiness row proposed_record_template must not allow PASS")
            if proposed_record_template.get("validation_output_command") != (
                f"cornerstone connector human-gate validate-record --scenario {scenario_id} "
                "--record-file <filled-json> --json --output <redacted-validation-envelope.json>"
            ):
                errors.append(
                    f"{scenario_id} human-gate readiness row proposed_record_template validation_output_command mismatch"
                )
            if proposed_record_template.get("record_template_output_command") != row.get(
                "record_template_output_command"
            ):
                errors.append(
                    f"{scenario_id} human-gate readiness row proposed_record_template record_template_output_command mismatch"
                )
            _validate_h04_field_ref_contract(
                errors,
                str(scenario_id),
                proposed_record_template.get("field_ref_contract"),
                context="readiness row proposed_record_template",
            )
            _validate_human_gate_redaction_guidance(
                errors,
                str(scenario_id),
                proposed_record_template.get("redaction_guidance"),
                required_fields=(
                    row.get("required_human_fields")
                    if isinstance(row.get("required_human_fields"), list)
                    else []
                ),
                required_evidence=(
                    proposed_record_template.get("required_evidence")
                    if isinstance(proposed_record_template.get("required_evidence"), list)
                    else []
                ),
                dependencies=(
                    row.get("depends_on_human_gates")
                    if isinstance(row.get("depends_on_human_gates"), list)
                    else []
                ),
                context="readiness row proposed_record_template",
            )
            _validate_human_gate_reviewer_checklist(
                errors,
                str(scenario_id),
                proposed_record_template.get("reviewer_checklist"),
                required_fields=(
                    row.get("required_human_fields")
                    if isinstance(row.get("required_human_fields"), list)
                    else []
                ),
                required_evidence=(
                    proposed_record_template.get("required_evidence")
                    if isinstance(proposed_record_template.get("required_evidence"), list)
                    else []
                ),
                dependencies=(
                    row.get("depends_on_human_gates")
                    if isinstance(row.get("depends_on_human_gates"), list)
                    else []
                ),
                record_template_output_command=row.get("record_template_output_command")
                if isinstance(row.get("record_template_output_command"), str)
                else "",
                validation_output_command=proposed_record_template.get("validation_output_command")
                if isinstance(proposed_record_template.get("validation_output_command"), str)
                else "",
                context="readiness row proposed_record_template",
            )
            row_validation_command = row.get("record_validation_command")
            row_plan_validation_command = (
                row_validation_command.replace("--record-file <json>", "--record-file <filled-json>")
                if isinstance(row_validation_command, str)
                else ""
            )
            _validate_human_gate_delivery_unit_plan(
                errors,
                str(scenario_id),
                row.get("scenario_delivery_unit_plan"),
                dependencies=(
                    row.get("depends_on_human_gates")
                    if isinstance(row.get("depends_on_human_gates"), list)
                    else []
                ),
                required_fields=(
                    row.get("required_human_fields")
                    if isinstance(row.get("required_human_fields"), list)
                    else []
                ),
                required_evidence=(
                    proposed_record_template.get("required_evidence")
                    if isinstance(proposed_record_template.get("required_evidence"), list)
                    else []
                ),
                package_command=row.get("package_command") if isinstance(row.get("package_command"), str) else "",
                record_template_output_command=row.get("record_template_output_command")
                if isinstance(row.get("record_template_output_command"), str)
                else "",
                validation_command=row_plan_validation_command,
                validation_output_command=proposed_record_template.get("validation_output_command")
                if isinstance(proposed_record_template.get("validation_output_command"), str)
                else "",
                context="readiness row",
            )
            _validate_human_gate_delivery_unit_plan_summary(
                errors,
                str(scenario_id),
                row.get("scenario_delivery_unit_plan_summary"),
                context="readiness row",
            )
            required_evidence = proposed_record_template.get("required_evidence")
            required_manifest = proposed_record_template.get("required_evidence_packet_manifest")
            record_template = proposed_record_template.get("record_template")
            if not isinstance(required_evidence, list) or not required_evidence:
                errors.append(f"{scenario_id} human-gate readiness row proposed_record_template missing evidence list")
            elif not isinstance(required_manifest, list) or len(required_manifest) != len(required_evidence):
                errors.append(f"{scenario_id} human-gate readiness row proposed_record_template manifest mismatch")
            elif [
                item.get("required_evidence_index")
                for item in required_manifest
                if isinstance(item, dict)
            ] != list(range(1, len(required_evidence) + 1)):
                errors.append(f"{scenario_id} human-gate readiness row proposed_record_template manifest indexes mismatch")
            elif [
                item.get("required_evidence")
                for item in required_manifest
                if isinstance(item, dict)
            ] != required_evidence:
                errors.append(f"{scenario_id} human-gate readiness row proposed_record_template manifest labels mismatch")
            if proposed_record_template.get("allowed_redaction_statuses") != [
                "redacted",
                "public_safe",
                "no_sensitive_material",
            ]:
                errors.append(f"{scenario_id} human-gate readiness row proposed_record_template redaction statuses mismatch")
            if not isinstance(record_template, dict):
                errors.append(f"{scenario_id} human-gate readiness row proposed_record_template missing record template")
            else:
                manifest_template = record_template.get("evidence_packet_manifest")
                if not isinstance(manifest_template, list) or len(manifest_template) != len(required_evidence or []):
                    errors.append(f"{scenario_id} human-gate readiness row proposed_record_template missing evidence manifest")
                elif any(
                    not isinstance(item, dict)
                    or item.get("evidence_ref") != ""
                    or item.get("redaction_status") != ""
                    or item.get("required_evidence") != required_evidence[index]
                    for index, item in enumerate(manifest_template)
                ):
                    errors.append(f"{scenario_id} human-gate readiness row proposed_record_template manifest must stay blank with labels")
            format_rules = proposed_record_template.get("format_rules")
            if not isinstance(format_rules, dict) or format_rules.get("review_timestamp") != (
                "ISO-8601 timestamp with timezone, for example 2026-06-24T12:00:00Z"
            ):
                errors.append(f"{scenario_id} human-gate readiness row proposed_record_template timestamp rule mismatch")
    validation_summary = report.get("record_validation_summary")
    if not isinstance(validation_summary, dict):
        errors.append("human-gate readiness report missing record_validation_summary")
    else:
        expected_structurally_valid = expected_validation_count
        expected_missing = [] if expected_validation_count == 7 else expected_human_ids
        expected_valid = expected_human_ids if expected_validation_count == 7 else []
        if validation_summary.get("validation_count") != expected_validation_count:
            errors.append(
                "human-gate readiness report record validation summary validation_count "
                f"expected {expected_validation_count}, found {validation_summary.get('validation_count')}"
            )
        if validation_summary.get("structurally_valid_count") != expected_structurally_valid:
            errors.append(
                "human-gate readiness report record validation summary structurally_valid_count "
                f"expected {expected_structurally_valid}, found {validation_summary.get('structurally_valid_count')}"
            )
        if validation_summary.get("structurally_invalid_count") != 0:
            errors.append("human-gate readiness report record validation summary must have no invalid records")
        if validation_summary.get("senior_review_perspective_findings_complete_count") != expected_validation_count:
            errors.append(
                "human-gate readiness report senior_review_perspective_findings_complete_count "
                f"expected {expected_validation_count}, "
                f"found {validation_summary.get('senior_review_perspective_findings_complete_count')}"
            )
        if validation_summary.get("senior_review_perspective_findings_incomplete_count") != 0:
            errors.append("human-gate readiness report senior_review_perspective_findings_incomplete_count must be zero")
        if validation_summary.get("evidence_packet_manifest_complete_count") != expected_validation_count:
            errors.append(
                "human-gate readiness report evidence_packet_manifest_complete_count "
                f"expected {expected_validation_count}, "
                f"found {validation_summary.get('evidence_packet_manifest_complete_count')}"
            )
        if validation_summary.get("evidence_packet_manifest_incomplete_count") != 0:
            errors.append("human-gate readiness report evidence_packet_manifest_incomplete_count must be zero")
        if validation_summary.get("scenarios_with_structurally_valid_record_validation") != expected_valid:
            errors.append(
                "human-gate readiness report structurally valid scenario list mismatch: "
                f"expected {expected_valid}, found {validation_summary.get('scenarios_with_structurally_valid_record_validation')}"
            )
        if validation_summary.get("scenarios_missing_structurally_valid_record_validation") != expected_missing:
            errors.append(
                "human-gate readiness report missing structurally valid scenario list mismatch: "
                f"expected {expected_missing}, found {validation_summary.get('scenarios_missing_structurally_valid_record_validation')}"
            )
        if validation_summary.get("dependency_unlock_allowed_count") != expected_validation_count:
            errors.append(
                "human-gate readiness report dependency_unlock_allowed_count "
                f"expected {expected_validation_count}, found {validation_summary.get('dependency_unlock_allowed_count')}"
            )
        if validation_summary.get("dependency_unlock_denied_count") != 0:
            errors.append("human-gate readiness report dependency_unlock_denied_count must be zero")
        if validation_summary.get("dependency_unlock_denied_record_validations") != []:
            errors.append("human-gate readiness report dependency unlock denied list must be empty")
        if validation_summary.get("scenarios_with_dependency_unlock_record_validation") != expected_valid:
            errors.append(
                "human-gate readiness report dependency unlock scenario list mismatch: "
                f"expected {expected_valid}, found {validation_summary.get('scenarios_with_dependency_unlock_record_validation')}"
            )
        if validation_summary.get("scenarios_missing_dependency_unlock_record_validation") != expected_missing:
            errors.append(
                "human-gate readiness report missing dependency unlock scenario list mismatch: "
                f"expected {expected_missing}, found {validation_summary.get('scenarios_missing_dependency_unlock_record_validation')}"
            )
        for key in [
            "product_claims_allowed_by_validations",
            "pass_claims_allowed_by_validations",
            "record_bodies_persisted_by_validations",
        ]:
            if validation_summary.get(key) != 0:
                errors.append(f"human-gate readiness report record validation summary must keep {key}=0")


def _validate_report_envelope(
    errors: list[str],
    label: str,
    report: dict[str, object],
    expected_report_path: Path,
    expected_git_commit: str | None = None,
) -> str | None:
    for key, expected_value in EXPECTED_REPORT_ENVELOPE.items():
        if report.get(key) != expected_value:
            errors.append(f"{label} {key} expected {expected_value}, found {report.get(key)}")
    ids = report.get("ids")
    if not isinstance(ids, dict):
        errors.append(f"{label} ids must be an object with git_commit")
        return None
    git_commit = ids.get("git_commit")
    if not isinstance(git_commit, str) or not git_commit.strip():
        errors.append(f"{label} ids.git_commit is required")
        return None
    if expected_git_commit and git_commit != expected_git_commit:
        errors.append(
            f"{label} ids.git_commit expected {expected_git_commit}, found {git_commit}"
        )
    expected_output_path = str(expected_report_path.resolve())
    if report.get("output_path") != expected_output_path:
        errors.append(
            f"{label} output_path expected {expected_output_path}, found {report.get('output_path')}"
        )
    expected_output_arg = expected_report_path.resolve().relative_to(ROOT.resolve()).as_posix()
    compact_report = report.get("compact_evidence_layout") == "content_addressed_shared_v1"
    transcript = report.get("self_command_transcript")
    if not isinstance(transcript, dict):
        errors.append(f"{label} self_command_transcript must be present")
        return git_commit
    if transcript.get("exit_code") != 0:
        errors.append(f"{label} self_command_transcript exit_code expected 0")
    command = transcript.get("command")
    if not isinstance(command, list):
        errors.append(f"{label} self_command_transcript command must be a list")
    else:
        for token in ["cornerstone", "scenario", "verify", "connector-contract-adapter", "--json"]:
            if token not in command:
                errors.append(f"{label} self_command_transcript command missing token: {token}")
        if "--output" not in command:
            errors.append(f"{label} self_command_transcript command missing token: --output")
        if compact_report:
            source_report = report.get("source_report")
            if not isinstance(source_report, dict):
                errors.append(f"{label} compact report missing source_report")
            else:
                source_path = source_report.get("path")
                if not isinstance(source_path, str) or not source_path:
                    errors.append(f"{label} compact source_report.path missing")
                elif source_path not in command:
                    errors.append(
                        f"{label} compact self_command_transcript command missing source output path: "
                        f"{source_path}"
                    )
        elif expected_output_arg not in command:
            errors.append(
                f"{label} self_command_transcript command missing output path: {expected_output_arg}"
            )
    return git_commit


def _validate_human_gate_package_contract(
    errors: list[str],
    ai_pass_rows: list[dict[str, str]],
    human_rows: list[dict[str, str]],
) -> None:
    for path, required_tokens in HUMAN_PACKAGE_CONTRACT_TOKENS.items():
        if not path.exists():
            errors.append(f"human-gate package contract source missing: {path.relative_to(ROOT)}")
            continue
        text = path.read_text()
        dynamic_tokens = []
        if path == CONTRACT_PATH:
            dynamic_tokens.append(_contract_matrix_state_source_token(ai_pass_rows, human_rows))
        for token in [*required_tokens, *dynamic_tokens]:
            if token not in text:
                errors.append(
                    "human-gate package contract missing token "
                    f"in {path.relative_to(ROOT)}: {token}"
                )
        for token in HUMAN_PACKAGE_CONTRACT_DISALLOWED_TOKENS.get(path, []):
            if token in text:
                errors.append(
                    "human-gate package contract contains stale token "
                    f"in {path.relative_to(ROOT)}: {token}"
                )


def _validate_connectorhub_scenario_registry(
    errors: list[str],
    matrix_rows: list[dict[str, str]],
) -> None:
    expected_scenarios = [
        {
            "id": row["scenario_id"],
            "type": row["type"],
            "title": row["title"],
            "expected_result": row["expected_result"],
            "verification_method": row["verification_method"],
            "owner": row["owner"],
        }
        for row in matrix_rows
    ]
    expected_ids = [row["id"] for row in expected_scenarios]

    for scenario_set in ["connectorhub", "connector-contract-adapter"]:
        payload = _run_cornerstone_json(
            errors,
            f"{scenario_set} scenario list",
            ["scenario", "list", "--set", scenario_set],
        )
        if payload is None:
            continue
        expected_fields = {
            "schema_version": "cs.cli.v0",
            "cli_schema_version": "cs.cli.v0",
            "product": "CornerStone",
            "mode": "local_scaffold",
            "command": "cornerstone scenario list",
            "status": "success",
            "scenario_set": scenario_set,
            "count": len(expected_scenarios),
        }
        for key, expected in expected_fields.items():
            if payload.get(key) != expected:
                errors.append(f"{scenario_set} scenario list {key} expected {expected}, found {payload.get(key)}")
        scenarios = payload.get("scenarios")
        observed_ids = [
            row.get("id", "")
            for row in scenarios
            if isinstance(row, dict)
        ] if isinstance(scenarios, list) else []
        if scenarios != expected_scenarios:
            errors.append(
                f"{scenario_set} scenario list must exactly match ConnectorHub matrix rows: "
                f"expected IDs {expected_ids}, found {observed_ids}"
            )
        if any(scenario_id not in observed_ids for scenario_id in sorted(EXPECTED_HUMAN_SCENARIO_IDS)):
            errors.append(f"{scenario_set} scenario list must include HUMAN_REQUIRED gate IDs")


def _manifest_summary_token(summary: dict[str, object], key: str) -> str:
    value = summary.get(key)
    if isinstance(value, list):
        value = ",".join(str(item) for item in value)
    return f"{key}={value}"


def _contract_matrix_state_source_token(
    ai_pass_rows: list[dict[str, str]],
    human_rows: list[dict[str, str]],
) -> str:
    return (
        "PASS and HUMAN_REQUIRED counts belong to generated reports, "
        "not this frozen contract header."
    )


def _contract_matrix_state_index_token(
    ai_pass_rows: list[dict[str, str]],
    human_rows: list[dict[str, str]],
) -> str:
    return (
        "contract status header must keep generated PASS/HUMAN_REQUIRED counts "
        "in reports, not in the frozen contract header"
    )


def main() -> int:
    errors: list[str] = []
    matrix_rows = _read_matrix()
    _validate_matrix_ledger(errors, matrix_rows)
    expected_matrix_row_count = len(EXPECTED_AI_SCENARIO_IDS | EXPECTED_HUMAN_SCENARIO_IDS)
    expected_ai_pass_count = len(EXPECTED_AI_SCENARIO_IDS)
    expected_human_required_count = len(EXPECTED_HUMAN_SCENARIO_IDS)
    ai_pass_rows = [
        row
        for row in matrix_rows
        if row.get("owner") == "AI" and row.get("status") == "PASS"
    ]
    human_rows = [
        row
        for row in matrix_rows
        if row.get("owner") == "Human" and row.get("status") == "HUMAN_REQUIRED"
    ]
    sorted_ai_pass_rows = sorted(ai_pass_rows, key=lambda item: _scenario_number(item["scenario_id"]))

    if len(matrix_rows) != expected_matrix_row_count:
        errors.append(
            f"expected {expected_matrix_row_count} ConnectorHub matrix rows, found {len(matrix_rows)}"
        )
    if len(ai_pass_rows) != expected_ai_pass_count:
        errors.append(f"expected {expected_ai_pass_count} AI PASS rows, found {len(ai_pass_rows)}")
    if len(human_rows) != expected_human_required_count:
        errors.append(
            f"expected {expected_human_required_count} HUMAN_REQUIRED rows, found {len(human_rows)}"
        )
    _validate_exact_artifact_sets(errors, matrix_rows)
    _validate_contract_proof_boundaries(errors, sorted_ai_pass_rows)
    _validate_makefile_targets(errors, sorted_ai_pass_rows)
    _validate_manifest_generator_contract(errors)
    _validate_readme_connectorhub_entrypoint(errors)
    _validate_connectorhub_scenario_registry(errors, matrix_rows)
    _validate_pinned_human_gate_package_reports(errors, human_rows)
    _validate_pinned_human_gate_readiness_report(errors, human_rows)
    _validate_pinned_human_gate_field_ref_contract_report(errors, human_rows)
    _validate_pinned_human_gate_evidence_packet_contract_report(errors, human_rows)
    _validate_pinned_human_gate_evidence_packet_file_contract_report(errors, human_rows)
    _validate_pinned_human_gate_evidence_packet_scaffold_report(errors, human_rows)
    _validate_pinned_human_gate_evidence_packet_validation_report(errors, human_rows)
    _validate_pinned_human_gate_evidence_packet_record_draft_report(errors, human_rows)
    _validate_pinned_human_gate_preflight_bundle_report(errors, human_rows)
    _validate_pinned_human_gate_next_report(errors, human_rows)
    _validate_pinned_human_gate_validation_handoff(errors, human_rows)

    covered_requirements: dict[str, list[str]] = {requirement: [] for requirement in SOURCE_REQUIREMENTS}
    unknown_requirements: dict[str, list[str]] = {}
    for row in matrix_rows:
        scenario_id = row.get("scenario_id", "")
        related_requirements = _requirement_ids(row.get("related_requirements", ""))
        proof_surface = row.get("proof_surface", "")
        claim_boundary = row.get("claim_boundary", "")
        if not related_requirements:
            errors.append(f"{scenario_id} has no related_requirements mapping")
        if not proof_surface:
            errors.append(f"{scenario_id} has no proof_surface mapping")
        if not claim_boundary:
            errors.append(f"{scenario_id} has no claim_boundary")
        if row.get("owner") == "Human":
            if proof_surface != "human_required":
                errors.append(f"{scenario_id} human row must use proof_surface=human_required")
            if row.get("status") != "HUMAN_REQUIRED" or "no AI PASS" not in claim_boundary:
                errors.append(f"{scenario_id} human row must preserve no-AI-PASS claim boundary")
        elif scenario_id == "CS-CH-036":
            if proof_surface != "local_vs2_topology":
                errors.append("CS-CH-036 must use proof_surface=local_vs2_topology")
            if "production network readiness" not in claim_boundary:
                errors.append("CS-CH-036 claim_boundary must reject production network readiness")
        else:
            if proof_surface != "local_fixture":
                errors.append(f"{scenario_id} AI fixture row must use proof_surface=local_fixture")
            boundary_text = claim_boundary.lower()
            for token in ["live-provider", "production", "human-acceptance"]:
                if token not in boundary_text:
                    errors.append(f"{scenario_id} claim_boundary must reject {token} claims")
        for requirement in related_requirements:
            if requirement in covered_requirements:
                covered_requirements[requirement].append(scenario_id)
            else:
                unknown_requirements.setdefault(requirement, []).append(scenario_id)
    for requirement, scenario_ids in unknown_requirements.items():
        errors.append(f"unknown source requirement {requirement} referenced by {', '.join(sorted(scenario_ids))}")
    for requirement, scenario_ids in covered_requirements.items():
        if not scenario_ids:
            errors.append(f"source requirement {requirement} is not mapped to any ConnectorHub scenario")
    source_requirement_coverage_trace = _source_requirement_coverage_trace(matrix_rows)

    if not AGGREGATE_REPORT_PATH.exists():
        errors.append(f"missing aggregate report: {AGGREGATE_REPORT_PATH.relative_to(ROOT)}")
        aggregate = {}
        aggregate_git_commit = None
    else:
        aggregate = _load_connector_contract_report(
            AGGREGATE_REPORT_PATH,
            errors,
            "aggregate connector report",
        )
        aggregate_git_commit = _validate_report_envelope(
            errors,
            "aggregate connector report",
            aggregate,
            AGGREGATE_REPORT_PATH,
        )
        summary = aggregate.get("summary", {})
        expected_aggregate_count = len(sorted_ai_pass_rows)
        if aggregate.get("status") != "success":
            errors.append("aggregate connector report is not success")
        if summary.get("scenario_count") != expected_aggregate_count:
            errors.append(
                "aggregate scenario_count expected "
                f"{expected_aggregate_count}, found {summary.get('scenario_count')}"
            )
        if summary.get("pass") != expected_aggregate_count:
            errors.append(
                f"aggregate pass expected {expected_aggregate_count}, "
                f"found {summary.get('pass')}"
            )
        if summary.get("blocking") != 0:
            errors.append(f"aggregate blocking expected 0, found {summary.get('blocking')}")
        if summary.get("human_required") != 0:
            errors.append("aggregate AI verifier should not count human rows as verified")
        if summary.get("product_feature_claims") != EXPECTED_CONNECTORHUB_PRODUCT_CLAIM:
            errors.append("aggregate product_feature_claims does not match current ConnectorHub proof boundary")
        _validate_scenario_gate(
            errors,
            "aggregate connector scenario gate",
            AGGREGATE_REPORT_PATH,
            expected_aggregate_count,
        )
        aggregate_results = aggregate.get("scenario_results", [])
        expected_aggregate_ids = [row["scenario_id"] for row in sorted_ai_pass_rows]
        aggregate_ids = [result.get("id") for result in aggregate_results]
        if aggregate_ids != expected_aggregate_ids:
            errors.append(
                "aggregate scenario_results IDs must exactly match sorted AI PASS matrix rows: "
                f"expected {expected_aggregate_ids}, found {aggregate_ids}"
            )
        if any(scenario_id in EXPECTED_HUMAN_SCENARIO_IDS for scenario_id in aggregate_ids):
            errors.append("aggregate scenario_results must not include HUMAN_REQUIRED rows")
        if len(set(aggregate_ids)) != len(aggregate_ids):
            errors.append("aggregate scenario_results contains duplicate scenario IDs")
        expected_rows_by_id = {row["scenario_id"]: row for row in sorted_ai_pass_rows}
        for result in aggregate_results:
            scenario_id = result.get("id", "")
            expected_row = expected_rows_by_id.get(scenario_id)
            if not expected_row:
                continue
            if result.get("status") != "PASS":
                errors.append(f"{scenario_id} aggregate row status expected PASS, found {result.get('status')}")
            if result.get("owner") != "AI":
                errors.append(f"{scenario_id} aggregate row owner expected AI, found {result.get('owner')}")
            if result.get("type") != expected_row.get("type"):
                errors.append(
                    f"{scenario_id} aggregate row type expected {expected_row.get('type')}, "
                    f"found {result.get('type')}"
                )
            if not result.get("evidence"):
                errors.append(f"{scenario_id} aggregate row must include evidence entries")
            if not result.get("notes"):
                errors.append(f"{scenario_id} aggregate row must include notes")

    for row in sorted_ai_pass_rows:
        scenario_id = row["scenario_id"]
        doc_path = VERIFICATION_DIR / f"CONNECTOR_HUB_{scenario_id.replace('-', '_')}_RESULT_2026-06-23.md"
        report_path = ROOT / row.get("evidence_required", "")
        if not doc_path.exists():
            errors.append(f"missing result doc for {scenario_id}: {doc_path.relative_to(ROOT)}")
            continue
        text = doc_path.read_text()
        stale_hits = [token for token in STALE_TOKENS if token in text]
        if stale_hits:
            errors.append(f"{scenario_id} result doc has stale aggregate metadata: {', '.join(stale_hits[:5])}")
        if scenario_id not in text:
            errors.append(f"{scenario_id} result doc does not mention its scenario ID")
        required_result_doc_tokens = {
            "matrix type": row.get("type", ""),
            "matrix phase": f"phase `{row.get('phase', '')}`",
            "related requirements": row.get("related_requirements", ""),
            "expected result": row.get("expected_result", ""),
            "verification method": row.get("verification_method", ""),
            "proof surface": row.get("proof_surface", ""),
            "claim boundary": row.get("claim_boundary", ""),
            "matrix evidence report": row.get("evidence_required", ""),
        }
        for label, token in required_result_doc_tokens.items():
            if token and str(token) not in text:
                errors.append(f"{scenario_id} result doc does not mention {label}: {token}")
        if "## Next Scenario" in text:
            errors.append(f"{scenario_id} result doc must not contain stale Next Scenario handoff")
        verification_section = _scenario_verification_section(text)
        cross_scenario_ids = sorted(
            found_id
            for found_id in set(re.findall(r"\bCS-CH-\d{3}\b", verification_section))
            if found_id != scenario_id
        )
        if cross_scenario_ids:
            errors.append(
                f"{scenario_id} Scenario Verification section references other scenarios: "
                f"{', '.join(cross_scenario_ids)}"
            )
        if "through CS-CH" in verification_section:
            errors.append(f"{scenario_id} Scenario Verification section uses cross-scenario range wording")
        missing_proof_anchors = _missing_result_doc_proof_anchors(text, row)
        if missing_proof_anchors:
            errors.append(
                f"{scenario_id} result doc lacks required proof anchors: "
                f"{', '.join(missing_proof_anchors)}"
            )
        _validate_ai_evidence_report(errors, row, report_path, aggregate_git_commit)
        missing_dimensions = _missing_decision_dimensions(text)
        if missing_dimensions:
            errors.append(
                f"{scenario_id} result doc lacks a complete Senior Engineering Decision Trail: "
                f"missing {', '.join(missing_dimensions)}"
            )
        missing_lifecycle_markers = _missing_lifecycle_markers(text)
        if missing_lifecycle_markers:
            errors.append(
                f"{scenario_id} result doc lacks a complete Scenario Lifecycle Trail: "
                f"missing {', '.join(missing_lifecycle_markers)}"
            )
        if "## Out Of Scope" not in text and "## Boundaries" not in text:
            errors.append(f"{scenario_id} result doc lacks proof boundary/out-of-scope section")

    for row in sorted(human_rows, key=lambda item: item["scenario_id"]):
        evidence_required = row.get("evidence_required", "")
        if "cornerstone connector human-gate report --json" not in evidence_required:
            errors.append(f"{row['scenario_id']} row does not reference the human-gate report")
        template_match = re.search(r"docs/verification-reports/CONNECTOR_HUB_CS_CH_H\d{2}_HUMAN_REVIEW_TEMPLATE_2026-06-24\.md", evidence_required)
        if not template_match:
            errors.append(f"{row['scenario_id']} row does not reference its human review template")
        else:
            template_path = ROOT / template_match.group(0)
            if not template_path.exists():
                errors.append(f"{row['scenario_id']} human review template missing: {template_match.group(0)}")
            else:
                template_text = template_path.read_text()
                for token in HUMAN_TEMPLATE_REQUIRED_TOKENS:
                    if token not in template_text:
                        errors.append(
                            f"{row['scenario_id']} human review template missing required token: {token}"
                        )
                if row["scenario_id"] not in template_text:
                    errors.append(f"{row['scenario_id']} human review template does not name the scenario ID")
                if "does not mark" not in template_text or "HUMAN_REQUIRED" not in template_text:
                    errors.append(
                        f"{row['scenario_id']} human review template lacks explicit no-PASS/HUMAN_REQUIRED boundary"
                    )
                if (
                    "## Scenario-First Execution Runbook" not in template_text
                    and "## Scenario-First Study Runbook" not in template_text
                ):
                    errors.append(
                        f"{row['scenario_id']} human review template lacks scenario-first runbook or study script"
                    )
                if "## Senior Review Perspectives" not in template_text:
                    errors.append(
                        f"{row['scenario_id']} human review template lacks senior review perspectives"
                    )
                for perspective_label in HUMAN_TEMPLATE_REQUIRED_PERSPECTIVE_LABELS:
                    if perspective_label not in template_text:
                        errors.append(
                            f"{row['scenario_id']} human review template missing senior perspective: "
                            f"{perspective_label}"
                        )
                if "Reject" not in template_text and "reject" not in template_text:
                    errors.append(f"{row['scenario_id']} human review template lacks reject conditions")
                _validate_human_template_submission_checklist(
                    errors,
                    row["scenario_id"],
                    template_text,
                )
                if row["scenario_id"] == "CS-CH-H04":
                    _validate_h04_template_handoff_snapshot(errors, template_text)
    if not HUMAN_PREPARATION_REPORT.exists():
        errors.append(f"missing human preparation report: {HUMAN_PREPARATION_REPORT.relative_to(ROOT)}")

    _validate_human_gate_package_contract(errors, ai_pass_rows, human_rows)
    _validate_human_gate_cli_readiness(errors, human_rows)
    _validate_pinned_blank_handoff_artifacts(errors)
    _validate_scenario_delivery_unit_manifest(errors, matrix_rows)

    if not ENGINEERING_TRAIL_INDEX.exists():
        errors.append(f"missing engineering trail index: {ENGINEERING_TRAIL_INDEX.relative_to(ROOT)}")
    else:
        index_text = ENGINEERING_TRAIL_INDEX.read_text()
        stale_hits = [token for token in STALE_TOKENS if token in index_text]
